const questions = [
  { cat: 4, q: "Kaj je izobata?", a: "Izobata je črta na pomorski karti, ki povezuje točke enakih globin. Pomaga nam oceniti obliko morskega dna in varno globino za plovbo, sidranje ali približevanje obali." },
  { cat: 2, q: "Kako naredimo in zakaj uporabljamo različne vozle?", a: "Vozle uporabljamo za privezovanje, spajanje vrvi, privez sidra, privez na bojo, izdelavo zanke in začasno skrajševanje vrvi. Najpomembnejši so:\n- osmica: zaključni vozel na koncu vrvi, da vrv ne zdrsne skozi oko ali škripec;\n- moški vozel: za spajanje dveh približno enako debelih vrvi; pazimo, da ne naredimo ženskega vozla, ker drsi;\n- zastavni vozel: za spajanje dveh vrvi, posebej kadar nista enako debeli;\n- sidrni vozel: za privez sidra;\n- vozel za bojo: za privez na rinko ali bojo;\n- pašnjak oziroma nezatezna zanka: za privez plovila na bitvo, ker se ne zadrgne in se ga lažje odveže;\n- vrzni vozel: za privez bokobranov na ograjo;\n- skrajševalni vozel: za hitro začasno skrajšanje vrvi ali izločitev poškodovanega dela vrvi." },
  { cat: 2, q: "Kaj je nadvodje?", a: "Nadvodje je navpična razdalja na boku plovila od vodne črte do zgornjega roba palube oziroma robnice. Večje nadvodje pomeni večjo varnostno rezervo pred zalivanjem plovila." },
  { cat: 2, q: "Zakaj in kje uporabljamo četverovez?", a: "Četverovez uporabljamo predvsem v pristaniščih in marinah, ker porabi malo obale: približno toliko, kolikor je čoln širok. Plovilo je privezano z vrvmi proti obali in proti morski strani, zato ostane stabilno na privezu." },
  { cat: 2, q: "Kaj je vodna črta?", a: "Vodna črta je črta, do katere sega voda na trupu plovila. Ločuje potopljeni del plovila od nadvodnega dela." },
  { cat: 5, q: "Kdaj je treba opraviti izredni pregled čolna?", a: "Izredni pregled je obvezen po izrednem dogodku, kot so trčenje, potopitev ali požar; po spremembi plovbnih lastnosti čolna, na primer podaljšanju, skrajšanju, razširitvi ali nadgradnji; ter kadar obstaja utemeljen sum, da čoln ni več sposoben za varno plovbo ali da njegovo stanje ne ustreza veljavnim listinam. O izrednem dogodku mora upravljalec oziroma lastnik takoj obvestiti pristojni organ, v opravičenih primerih pa najpozneje v treh dneh." },
  { cat: 2, q: "Če se sidramo med drugimi že zasidranimi plovili, kaj moramo upoštevati?", a: "Upoštevati moramo, da se zasidrano plovilo zaradi vetra in toka obrača okoli točke sidranja. Zato izberemo dovolj veliko varnostno razdaljo in upoštevamo polmer obračanja svojega plovila ter sosednjih plovil." },
  { cat: 5, q: "Koliko se smejo oddaljiti od obale čolni na v vesla, neregistrirani čolni (čoln, ki niso vpisani v vpisnik čolnov, kot so kajak, vodno kolo, čoln na vesla, jadralec na deski...?", a: "Navedena plovila se smejo oddaljiti do 1000 m od obale." },
  { cat: 3, q: "Kako ravnamo pri uporabi novega motorja?", a: "Pri uporabi novega motorja se ravnamo po navodilih proizvajalca. Posebej upoštevamo navodila za utekanje motorja, pravilno gorivo, olje, dovoljene obrate, servisne intervale in nadzor hlajenja." },
  { cat: 3, q: "Kaj se zgodi, če je toplotna vrednost svečke premajhna?", a: "Če je toplotna vrednost svečke premajhna, se svečka preveč segreva. Pri večjih obremenitvah lahko zaradi žarenja svečke pride do samovžiga zmesi, neenakomernega delovanja motorja ali poškodb motorja." },
  { cat: 2, q: "Kakšna mora biti najmanjša dimenzija črk in številk označbe čolna?", a: "Črke in številke označbe čolna morajo biti visoke najmanj 10 cm, široke 5 cm, širina črt mora biti 1 cm, medsebojna razdalja pa 1 cm. Če so oznake večje, mora biti ohranjeno isto razmerje. Črke in številke morajo biti med seboj ločene s pomišljajem. Za ribiške čolne veljajo posebne večje mere glede na dolžino čolna." },
  { cat: 2, q: "Kako se imenujejo privezne vrvi pri privezu čolna ob obalo?", a: "Privezne vrvi dobijo ime po svoji funkciji na privezu. Poznamo premčno vrv, krmno vrv, premčno in krmno bočno vrv oziroma tresin ter sprednji in zadnji špring. Špring preprečuje premikanje plovila naprej ali nazaj ob obali." },
  { cat: 3, q: "Kaj je vzrok, da se plovilo s krmnim motorjem ne premakne kljub temu, da motor deluje?", a: "Najpogostejši vzrok je prekinjen varovalni zatič ali poškodovan prenos na propelerju. Motor in os se vrtita, propeler pa ne prenaša sile na vodo. Zatič se lahko prelomi ob udarcu propelerja v trd predmet ali ob nenadni obremenitvi, na primer ko motor pri valovih pride iz vode in nato ponovno zagrabi vodo. Zato je priporočljivo imeti na plovilu rezervni zatič in ustrezno orodje." },
  { cat: 6, q: "Kateri zvočni signal pomeni »moji stroji delujejo nazaj«?", a: "Trije kratki piski pomenijo: »Moji stroji delujejo nazaj.« Signal pove, da plovilo uporablja pogon za vožnjo nazaj oziroma za zaustavljanje z delovanjem strojev nazaj." },
  { cat: 4, q: "Kaj je premčev kot (L)?", a: "Premčev kot je kot med vzdolžnico plovila v smeri plovbe in smerjo proti opazovanemu objektu. Meri se od premca proti krmi do 180° po desni ali levi strani. Za določanje premčevega kota ne potrebujemo kompasa; z njim pa lahko iz kurza izračunamo azimut objekta." },
  { cat: 5, q: "Koliko najmanj mora od obale pluti ladja?", a: "Ladja mora pluti najmanj 300 m od obale, razen kadar vpluje ali izpluje iz pristanišča, sidrišča ali kadar druga pravila določajo drugače." },
  { cat: 5, q: "Katere osnovne podatke vsebuje vpisni list?", a: "Vpisni list praviloma vsebuje podatke o organu, ki je listino izdal, označbo in ime čolna, podatke o čolnu in motorju, podatke o posadki, namenu uporabe in območju plovbe, podatke o lastniku, morebitne obremenitve in opombe ter dovoljenje za plovbo." },
  { cat: 5, q: "Kdaj je treba opraviti osnovni pregled čolna?", a: "Osnovni pregled se opravi pred vpisom čolna v vpisnik in tudi po vsaki njegovi obnovi ali rekonstrukciji.\nPri tem se opravijo tudi izmeritve čolna." },
  { cat: 3, q: "Kakšni so varnostni ukrepi v času polnjenja goriva v rezervar plovila?", a: "Med polnjenjem goriva moramo preveriti pravo vrsto goriva, ugasniti motor, prepovedati kajenje in odprt ogenj, zapreti odprtine proti bivalnim prostorom, dobro prezračiti prostor motorja in rezervoarja ter imeti pripravljen gasilni aparat. Posebej nevarni so bencinski hlapi, ker so vnetljivi in se lahko zadržujejo v nižjih delih plovila." },
  { cat: 6, q: "Kateri zvočni signal pomeni »zavijam desno«?", a: "En kratek pisk pomeni: »Zavijam desno.«" },
  { cat: 5, q: "Kateri čolni morajo izobesiti zastavo državne pripadnosti?", a: "Zastavo državne pripadnosti morajo izobesiti čolni državnih organov. Čolni za osebne namene je v domačih vodah praviloma ne izobešajo obvezno, pri plovbi v tujih notranjih morskih vodah pa izobesijo svojo državno zastavo in zastavo države gostiteljice." },
  { cat: 4, q: "Kaj je devijacija (δ)?", a: "Devijacija je kot med magnetnim meridianom in kompasnim meridianom. Nastane zaradi ladijskega magnetizma, torej vpliva kovinskih delov, električnih naprav in druge opreme na kompas. Podatke o devijaciji za posamezne kurze dobimo iz tablice devijacije, izdelane za konkretno plovilo." },
  { cat: 3, q: "Kaj storimo, če nam izvenkrmni motor ne vžge?", a: "Najprej preverimo osnovne vzroke: ali je v rezervoarju dovolj goriva, ali je odprt dovod goriva in zračnik rezervoarja, ali gorivo prihaja do uplinjača oziroma sistema vbrizga, ali je svečka čista in ali ima iskro. Preverimo tudi položaj ročice menjalnika, varnostno stikalo in morebitne vidne poškodbe kablov ali cevi." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da imamo namen prehitevati drugo plovilo po desni?", a: "Dva dolga in en kratek pisk pomenijo, da nameravamo v ožini ali kanalu prehitevati po desni strani drugega plovila." },
  { cat: 6, q: "Katero plovilo se mora izogibati v primeru, če jadrnica prehiteva motorni čoln in obstaja nevarnost trčenja?", a: "Izogiba se plovilo, ki prehiteva. Če jadrnica prehiteva motorni čoln, se mora izogibati jadrnica, čeprav ima sicer jadrnica pogosto prednost pred motornim plovilom." },
  { cat: 3, q: "Kateri so osnovni nadomestni deli, ki jih je priporočljivo imeti v plovilu?", a: "Priporočljivi nadomestni deli so vžigalne svečke, zatiči za propeler pri izvenkrmnem motorju, jermen pri vgrajenem motorju, impeler vodne črpalke, cevi za gorivo, filter goriva, objemke različnih dimenzij in rezervne žarnice za navigacijske luči." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je ladja nesposobna za manevriranje, oz. da je ladja z omejeno sposobnostjo manevriranja, omejena z ugrezom, ribiška ladja, da je jadrnica ali vlačilec ko vleče?", a: "Trije zvoki drug za drugim, od tega prvi dolg in dva kratka v intervalu ne več kot 2 minute." },
  { cat: 4, q: "Kakšen pribor uporabljamo za delo na karti pri vodenju navigacije?", a: "Za delo na pomorski karti uporabljamo dva navtična trikotnika za risanje in branje kurzov ter azimutov, navtično šestilo za merjenje in prenašanje razdalj ter za vrisovanje oziroma branje geografskih koordinat, svinčnik in radirko." },
  { cat: 1, q: "Kaj je levante?", a: "Levante je prehoden, vlažen vzhodni veter, značilen predvsem za severni Jadran. Najpogosteje nastane v zimskem času, pogosto v brezvetrju, in lahko preide v burjo ali jugo." },
  { cat: 6, q: "Kakšna je dolžnost plovila napram drugemu, ki se mora izogibati?", a: "Plovilo, ki ima prednost, mora praviloma ohraniti smer in hitrost, da je njegov namen drugemu plovilu jasen. Če pa postane očitno, da se plovilo, ki bi se moralo izogibati, ne izogiba ustrezno, mora tudi plovilo s prednostjo ukrepati, da prepreči trčenje." },
  { cat: 4, q: "Kaj so posebne oznake IALA?", a: "Posebne oznake IALA niso namenjene neposrednemu vodenju plovbe po varni vodi, ampak označujejo posebna območja ali objekte. Z njimi so lahko označeni kabli, cevovodi, rekreativna območja, raziskovalne postaje, zavarovana območja ali druga območja, opisana v pomorskih kartah in publikacijah." },
  { cat: 3, q: "Kaj je vžigalna svečka in čemu služi?", a: "Vžigalna svečka je zaključni del vžigalne naprave pri bencinskem motorju. Privita je v glavo motorja, sprejme visoko napetost in v zgorevalnem prostoru ustvari iskro, ki vžge zmes bencina in zraka." },
  { cat: 3, q: "Kakšne vrste hlajenja motorja se uporablja?", a: "Pri motorjih na plovilih se uporabljata zračno in vodno hlajenje. Vodno hlajenje je lahko odprto, kjer morska voda kroži skozi sistem in odteče nazaj v morje, ali zaprto, kjer hladilna tekočina kroži po motorju in jo prek izmenjevalnika hladi morska voda." },
  { cat: 5, q: "Kakšne morajo biti dimenzije označbe na gliserju?", a: "Na gliserju morajo biti črke in številke označbe visoke najmanj 20 cm, široke 10 cm, širina linij mora biti 2 cm, medsebojna razdalja pa 2 cm. Če so mere večje, mora biti ohranjeno predpisano razmerje." },
  { cat: 1, q: "Kaj je maestral?", a: "Maestral je prijeten priobalni termični veter, ki nastane podnevi, ker se kopno segreva hitreje kot morje. Piha z morja proti kopnemu, pri nas pogosto iz smeri WNW, drugod po Jadranu tudi iz smeri NW. Običajno začne pihati dopoldne, najmočnejši je zgodaj popoldne in oslabi pred sončnim zahodom." },
  { cat: 5, q: "Kako mora biti označeno mesto potapljanja (potapljač pod vodo)?", a: "Mesto potapljanja je lahko označeno z zastavo A mednarodnega signalnega kodeksa na plovilu ali boji. Športni potapljači pogosto uporabljajo oranžno bojo s potapljaško zastavico. Pluti moramo počasi in na varni razdalji, praviloma vsaj 50 m od oznake, da ne ogrozimo potapljača." },
  { cat: 3, q: "Katere so bistvene razlike med dizel in bencinskim (OTTO) motorjem?", a: "Bistvena razlika je v gorivu in v pripravi in vžigu goriva." },
  { cat: 5, q: "Koliko mora biti stara oseba in kakšen izpit mora imeti, če želi upravljati: motorni čoln, gliser, čoln dolžine do 7 m z motorjem do 7,35 kW in vodni skuter?", a: "Motorni čoln lahko upravlja oseba, stara najmanj 16 let, z opravljenim izpitom za voditelja čolna. Gliser lahko upravlja oseba, stara najmanj 18 let, z opravljenim izpitom za voditelja čolna. Čoln do 7 m z motorjem do 7,35 kW in vodni skuter lahko upravlja oseba, stara najmanj 16 let, z opravljenim predpisanim preizkusom znanja oziroma ustreznim dovoljenjem." },
  { cat: 3, q: "Kaj je narobe, če nam dizel motor ugasne?", a: "Če dizelski motor sam od sebe ugasne, je najpogostejši vzrok pomanjkanje goriva, voda ali zrak v sistemu goriva, zamašen filter ali prekinjen dovod goriva. Sistem je treba pregledati, po potrebi odzračiti in odpraviti vzrok." },
  { cat: 5, q: "Katera dejanja so prepovedana v pristaniščih?", a: "V pristaniščih so prepovedana dejanja, ki ogrožajo varnost, red ali čistočo: samovoljno premeščanje tujih priveznih vrvi in sider, oviranje dostopa do privezov, privezovanje na neustrezne naprave, poškodovanje pristaniških označb, kurjenje odprtega ognja brez dovoljenja, onesnaževanje morja, izpuščanje fekalnih voda, nepotrebno delovanje ladijskega vijaka in uporaba priveznih mest za potopljena, nasedla ali nevarno poškodovana plovila." },
  { cat: 5, q: "Kaj so pomorski prekrški?", a: "Pomorski prekrški so kršitve predpisov s področja pomorstva, varnosti plovbe, reda v pristaniščih, varstva morja in predpisane opreme ter listin plovila." },
  { cat: 2, q: "Od česa je odvisna stabilnost čolna?", a: "Stabilnost čolna je odvisna predvsem od oblike trupa, težišča plovila, razporeditve oseb in tovora, količine tekočin v rezervoarjih ter vpliva vetra in valov. Težji tovor mora biti razporejen nizko, enakomerno in pritrjen." },
  { cat: 5, q: "Kdaj prekrški prerastejo v kaznivo dejanje?", a: "Prekrški lahko prerastejo v kaznivo dejanje, kadar gre za hujše kršitve, ki povzročijo večjo materialno škodo, težje telesne poškodbe, smrt ali resno ogrožanje človeških življenj." },
  { cat: 1, q: "Naštej imena vetrov, ki pihajo na Jadranskem morju?", a: "Glavni vetrovi na Jadranu so:\n- tramontana: severnik (N);\n- burin: sever-severovzhodnik (NNE);\n- burja: severovzhodnik (NE);\n- levante: vzhodnik (E);\n- jugo oziroma široko: jugovzhodnik (SE);\n- oštro: južnik (S);\n- lebič oziroma garbin: jugozahodnik (SW);\n- ponente: zahodnik (W);\n- maestral: severozahodnik (NW)." },
  { cat: 1, q: "Kako delimo oblake?", a: "Oblake delimo po višini na visoke, srednje in nizke oblake, po obliki pa na ciruse, kumuluse, stratuse in njihove kombinacije. Za varnost plovbe je posebej pomemben kumulonimbus, ker napoveduje nevihto, močne padavine, sunke vetra in možnost toče." },
  { cat: 5, q: "Koliko najmanj mora od obale pluti motorni čoln, ki ne glisira?", a: "Motorni čoln, ki ne glisira, mora pluti najmanj 200 m od obale, razen pri vplutju, izplutju ali kadar druga lokalna pravila določajo drugače." },
  { cat: 3, q: "Kako zaustavimo delovanje motorja?", a: "Bencinski motor običajno zaustavimo s prekinitvijo električnega vžiga, dizelski motor pa s prekinitvijo dovoda goriva. To se izvede s stikalom, ključem, gumbom za zaustavitev ali premikom ročice za dovod goriva v zaprt položaj." },
  { cat: 2, q: "Kaj se ugotavlja s pregledom čolna?", a: "S pregledom se ugotavlja, ali je čoln po konstrukciji, plovnih lastnostih, opremi, motorju in listinah sposoben za varno plovbo v določenem območju plovbe." },
  { cat: 5, q: "Kdo izvaja nadzor nad varnostjo plovbe?", a: "Nadzor nad varnostjo plovbe izvaja Uprava Republike Slovenije za pomorstvo s pristaniškimi nadzorniki in pomorskimi inšpektorji oziroma drugimi pristojnimi pooblaščenimi osebami." },
  { cat: 6, q: "Kako se mora izogibati plovilo, ki se je dolžno izogibati?", a: "Plovilo, ki se je dolžno izogibati, mora ukrepati pravočasno, odločno in jasno. Praviloma ne sme sekati poti po premcu plovilu, ki ima prednost, ampak se mora umakniti tako, da je izogibanje varno in razumljivo." },
  { cat: 6, q: "Kaj predstavlja bela luč?", a: "Bela luč lahko pomeni krmno luč plovila, zasidrano plovilo, belo krožno luč manjšega plovila ali druge posebne položaje glede na kombinacijo z drugimi lučmi. Samo bela luč zato ni dovolj za popolno identifikacijo; pomembni so tudi kot vidnosti, položaj luči in druge luči na plovilu." },
  { cat: 3, q: "Na kaj moramo paziti pri pripravi izvenkrmnega motorja za zagon?", a: "Pred zagonom izvenkrmnega motorja preverimo, ali je motor dobro pritrjen, ali je dovolj goriva, ali je odprt dovod goriva in zračnik rezervoarja, ali je ročica menjalnika v nevtralnem položaju in ali je pravilno nastavljena loputa za zrak oziroma čok. Po zagonu odpremo čok, pustimo motor, da se ogreje, in preverimo iztok hladilne vode." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da se ladja približuje zavoju?", a: "En dolg pisk pomeni, da se ladja v ožini ali kanalu približuje zavoju oziroma nepreglednemu delu poti. Druga ladja mora odgovoriti z enakim dolgim piskom." },
  { cat: 2, q: "Iz katerih materialov so grajeni čolni?", a: "Čolni so lahko grajeni iz lesa, kovine, plastike, gume, armiranega betona ali kombinacije materialov, na primer guma-plastika ali guma-aluminij. Material vpliva na vzdrževanje, težo, trajnost in način popravil." },
  { cat: 1, q: "Kaj storimo, ko opazimo prve znake približevanja nevihte?", a: "Čim prej poiščemo varno zavetje, zmanjšamo izpostavljenost vetru in valovom, preverimo privez opreme, pripravimo rešilne jopiče in se izognemo nadaljevanju plovbe proti odprtemu morju." },
  { cat: 2, q: "Katere vrste pregledov čolna poznamo?", a: "Poznamo osnovni, redni in izredni pregled čolna. Osnovni pregled se opravi pred vpisom, redni pregled v predpisanih časovnih presledkih, izredni pregled pa po izrednem dogodku ali spremembi čolna." },
  { cat: 2, q: "Kateri so sestavni deli čolna?", a: "Glavni sestavni deli čolna so gredelj, premčeva in krmna grodnica, rebra, oplata ter paluba. Če je čoln odprtega tipa in nima palube, je zgornji rob običajno zaključen z robnico." },
  { cat: 4, q: "Kakšne priročnike za plovbo poznate?", a: "Pri plovbi uporabljamo sezname svetilnikov, sezname radijskih svetilnikov, navtične letnike, vodnike za plovbo, tablice morskih men, kataloge pomorskih kart, sezname kratic in znakov ter obvestila za pomorščake." },
  { cat: 5, q: "Kdaj mora izobesiti zastavo državne pripadnosti čoln, ki služi za osebne namene?", a: "Čoln za osebne namene mora izobesiti zastavo državne pripadnosti predvsem pri plovbi v tujih notranjih morskih vodah. Običajno ima na krmi svojo zastavo, na jamboru ali drugem višjem delu pa zastavo države gostiteljice." },
  { cat: 4, q: "Kaj so kardinalne oznake IALA?", a: "Kardinalne oznake kažejo, na kateri strani oznake je varna oziroma najgloblja voda. Severna oznaka pomeni, da je varna voda severno od oznake, vzhodna vzhodno, južna južno in zahodna zahodno. Prepoznamo jih po rumeno-črni barvi in vrhnjih znamenjih iz dveh stožcev." },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi z vetrom v krmo?", a: "Pri plovbi z vetrom v krmo čoln slabše drži smer, lahko se ziblje in ga valovi potiskajo od zadaj. Pri močnejših valovih lahko propeler občasno pride iz vode, kar povzroči tresljaje in neenakomeren potisk." },
  { cat: 3, q: "Na kaj moramo biti pozorni pri delovanju motorja med plovbo?", a: "Med plovbo spremljamo zvok in tresljaje motorja, temperaturo, pritisk olja, polnjenje akumulatorja, količino goriva, iztok hladilne vode in morebitne alarme. Ob nenavadnem zvoku, pregrevanju ali opozorilni lučki zmanjšamo obrate in poiščemo vzrok." },
  { cat: 5, q: "Kateri organ v R Sloveniji vodi vpisnik morskih čolnov?", a: "Vpisnik morskih čolnov vodi Uprava RS za pomorstvo Koper in njeni izpostavi v Izoli in Piranu." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je ladja na mehanični pogon v plovbi?", a: "En dolg zvok v intervalih ne več kot 2 minute." },
  { cat: 2, q: "Kako delimo čolne?", a: "Čolne delimo po obliki trupa, vrsti pogona, namenu in materialu gradnje. Po obliki poznamo spodrivne, polspodrivne in drsne čolne, po trupu pa enotrupne, dvotrupne in tritrupne čolne." },
  { cat: 5, q: "Kaj obsegajo notranje morske vode?", a: "Notranje morske vode obsegajo morje med obalo in temeljno črto teritorialnega morja. Sem spadajo tudi zalivi, pristanišča in vode med kopnim ter črto, ki povezuje skrajne zunanje točke obale oziroma otokov." },
  { cat: 4, q: "Kaj pomeni, če se pri križanju kurzev dveh plovil premčev kot ali azimut spreminja?", a: "Če se premčev kot ali azimut povečuje, bo opazovano plovilo praviloma šlo mimo za krmo našega plovila. Če se premčev kot ali azimut zmanjšuje, bo plovilo praviloma šlo mimo pred našim premcem. Če se ne spreminja bistveno, obstaja nevarnost trčenja." },
  { cat: 4, q: "Kaj razumemo kot plovbo v težjih pogojih?", a: "Plovba v težjih pogojih je plovba v okoliščinah, ki zahtevajo večjo previdnost: v megli, dežju, močnem vetru, visokih valovih, kanalih, ožinah, pri plovbi mimo ovir, pod mostovi ali v gostem prometu." },
  { cat: 3, q: "Kako delimo motorje z notranjim izgorevanjem?", a: "Motorje z notranjim izgorevanjem delimo po gorivu in načinu vžiga na bencinske oziroma OTTO motorje in dizelske motorje; po načinu delovanja na dvotaktne in štiritaktne; po hlajenju pa na zračno in vodno hlajene motorje." },
  { cat: 3, q: "Kdaj ugasnemo motor pri pristajanju čolna?", a: "Motor pri pristajanju ugasnemo šele, ko je čoln varno ob obali in dokončno privezan. Do takrat mora biti motor pripravljen za manevriranje, popravljanje položaja ali zaustavljanje plovila." },
  { cat: 3, q: "Kaj je narobe, če motor teče neenakomerno in izpušča takte?", a: "Če motor teče neenakomerno in izpušča takte, je lahko vzrok nedelujoča ali umazana svečka, poškodovani kabli vžiga, nepravilna zmes goriva in zraka, umazan filter ali moten dovod goriva." },
  { cat: 2, q: "Kaj je ugrez?", a: "Ugrez je navpična razdalja med vodno črto in najnižjo točko plovila. Pomemben je pri plovbi v plitvini, vplutju v pristanišča, sidranju in oceni nevarnosti nasedanja." },
  { cat: 3, q: "Zakaj je pomembno, kakšno svečko bomo privili glede na dolžino navoja?", a: "Dolžina navoja svečke mora ustrezati motorju. Če v motor, predviden za kratki navoj, privijemo svečko z dolgim navojem, lahko svečka sega pregloboko v zgorevalni prostor in poškoduje bat ali ventile." },
  { cat: 2, q: "Kaj je četverovez?", a: "Četverovez je način priveza plovila s štirimi vrvmi. Dve vrvi sta praviloma privezani proti obali, dve pa proti morski strani, na bojo, sidro ali privezne elemente v marini. Proti obali je lahko obrnjen premec ali krma." },
  { cat: 3, q: "Kaj se zgodi, če je toplotna vrednost svečke previsoka?", a: "Če je toplotna vrednost svečke previsoka, svečka ne doseže primerne delovne temperature. Zaradi tega se lahko zapacka, iskra postane slabša in motor deluje neenakomerno ali težje vžge." },
  { cat: 2, q: "Kako se meri širina čolna?", a: "Širina čolna se meri na najširšem delu, običajno na glavnem rebru, med zunanjima robovoma oplate." },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi proti vetru?", a: "Pri plovbi proti vetru in valovom se hitrost zmanjša, čoln se vzdolžno guga, propeler lahko deluje neenakomerno, konstrukcija pa je bolj obremenjena. Priporočljivo je pluti nekoliko poševno glede na veter in valove, ne neposredno v najhujše udarce." },
  { cat: 5, q: "Katera je predpisana oprema in območje plovbe za čoln do 5 m dolžine?", a: "Čoln do 5 m dolžine ima predpisano osnovno varnostno opremo glede na območje plovbe, namen uporabe in pogon. Med osnovno opremo običajno spadajo vesla ali drugo pomožno pogonsko sredstvo, privezna vrv, sidro z vrvjo, črpalka ali posoda za izčrpavanje vode, rešilna sredstva, luči, če pluje ponoči, in predpisana dokumentacija. Natančen seznam je odvisen od veljavnih predpisov in vpisanega območja plovbe." },
  { cat: 2, q: "Kakšna sredstva uporabljamo za reševanje oseb iz vode?", a: "Za reševanje oseb iz vode uporabljamo rešilni obroč, lahko z vrvjo, lučjo ali dimnim signalom, rešilni pas, rešilni jopič, rešilni splav, napihljive blazine, vrvi in druga plavajoča sredstva. Pomembno je, da so sredstva hitro dostopna in uporabna tudi v slabem vremenu." },
  { cat: 4, q: "Kaj je sistem pomorskih oznak IALA?", a: "Sistem IALA določa pravila za fiksne in plavajoče pomorske oznake. Pozna laterarne oznake, kardinalne oznake, oznake osamljene nevarnosti, oznake varnih voda in posebne oznake. Namen sistema je, da pomorščak iz oblike, barve, vrhnjega znamenja in luči razbere, kje je varna plovna pot oziroma nevarnost." },
  { cat: 2, q: "Kako lahko preventivno ukrepamo, da preprečimo požar na plovilu?", a: "Požar preprečujemo z rednim vzdrževanjem električne napeljave in motorja, pravilnim ravnanjem z gorivom, prezračevanjem motornega prostora, prepovedjo kajenja pri gorivu, varno uporabo plinskih naprav, odstranjevanjem mastnih krp in gorljivih odpadkov ter s pripravljenimi in pregledanimi gasilnimi aparati." },
  { cat: 6, q: "Kakšen mora biti manever izogibanja?", a: "Manever izogibanja mora biti pravočasen, odločen in dovolj velik, da je drugemu plovilu jasno, kaj nameravamo storiti. Sprememba smeri ali hitrosti ne sme biti majhna in dvoumna. Vedno se izogibamo tako, da povečamo varnostno razdaljo." },
  { cat: 2, q: "Kako mora biti razporejen tovor na čolnu?", a: "Tovor mora biti enakomerno razporejen, čim nižje v plovilu in dobro pritrjen. Ne sme ovirati gibanja posadke, dostopa do varnostne opreme ali vidljivosti voditelja čolna. Neenakomeren ali visok tovor zmanjšuje stabilnost." },
  { cat: 5, q: "Katera je predpisana oprema in območje plovbe za čoln nad 5 m in čoln s kabino do 7 m dolžine?", a: "Za čoln dolžine nad 5 m in čoln do 7 m s kabino je predpisan minimum opreme:\nsidro z najmanj 30 metrov dolgo vrvjo ali verigo za sidranje in tri vrvi za privez skupne dolžine najmanj 40 metrov ustrezne jakosti\n- pomožno pogonsko napravo (motor ali jadra) ali VHF GMDSS postajo ali tri rdeče rakete s padalom\n- vedro s korcem ali ročno črpalko\n- luči in dnevne oznake po predpisih o izogibanju trčenju na morju\n- konveksno ogledalo (le gliser, ki se uporablja za smučanje na vodi)\n- tri rdeče bakle\n- kompas\nMed plovbo mora imeti rešilne jopiče v tolikšnem številu, kolikor oseb se nahaja na čolnu.\nObmočje plovbe je obalno območje do 4Nm proti odprtemu morju, merjeno od osnovne črte teritorialnega morja." },
  { cat: 2, q: "Kaj so lahko vzroki požara na čolnu?", a: "Vzroki požara so lahko odprt ogenj, kajenje, kratek stik na električni napeljavi, nepravilno ravnanje z gorivom, bencinski hlapi, slabo prezračevanje strojnice, okvare motorja, pregrevanje, trčenje ali nepravilna uporaba plinskih in električnih naprav." },
  { cat: 2, q: "Kako izplujemo iz priveznega mesta?", a: "Pred izplutjem prižgemo motor, preverimo delovanje krmila in pogona, pripravimo posadko, preverimo veter, tok in ovire okoli plovila. Nato odvežemo vrvi v pravilnem zaporedju, po potrebi se odrinemo s čolnarskim kavljem in počasi izplujemo, ne da bi poškodovali sosednja plovila ali privezne vrvi." },
  { cat: 4, q: "Kaj so laterarne oznake IALA?", a: "Laterarne oznake označujejo levo in desno stran plovne poti ali kanala. V coni A, kamor spada Evropa, je leva stran pri vplutju označena z rdečo barvo, desna pa z zeleno. Pri izplutju se strani zamenjata glede na smer plovbe." },
  { cat: 1, q: "Kaj so poletne vročinske nevihte?", a: "Poletne vročinske nevihte so lokalne nevihte, pogoste predvsem v severnem Jadranu. Nastanejo ob soparnem, toplem in mirnem vremenu. Približevanje nakazujejo temni kopasti oblaki, razvoj kumulonimbusa, padanje zračnega tlaka, grmenje, bliskanje, nalivi in močni sunki vetra. Običajno so kratkotrajne, vendar so za majhna plovila nevarne." },
  { cat: 4, q: "Pomorske oznake IALA v slovenskem morju?", a: "V slovenskem morju se uporabljajo laterarne oznake pri vhodih v pristanišča in kanale, kardinalna oznaka pri Debelem rtiču, oznaka varnih voda v Koprskem zalivu ter posebne oznake, na primer rumene boje za zavarovana območja pri Debelem rtiču, Belih skalah in rtu Madona." },
  { cat: 5, q: "Katerih čolnov ni treba vpisati v vpisnik čolnov?", a: "V vpisnik čolnov praviloma ni treba vpisati čolna, krajšega od 3 m, razen če ima motorni pogon z močjo več kot 3,7 kW. Pri posebnih primerih je treba preveriti veljavne predpise." },
  { cat: 4, q: "Katere objekte izbiramo pri določanju položaja čolna s pomočjo azimutov?", a: "Za določanje položaja z azimuti izbiramo dobro vidne in na karti vrisane objekte, kot so svetilniki, rti, zvoniki, cerkve, stolpi, dimniki, gradovi ali izraziti vrhovi. Objekt mora biti dovolj jasno prepoznaven, da ne pride do zamenjave." },
  { cat: 3, q: "Katere so dobre in slabe lastnosti vgrajenih motorjev?", a: "Dobre lastnosti vgrajenih motorjev so miren tek, večja stabilnost, daljša življenjska doba in možnost večjih moči. Slabe lastnosti so večja poraba prostora v čolnu, težji dostop za vzdrževanje, zahtevnejša konstrukcija plovila in lahko slabši izkoristek vijaka zaradi nagnjene osi." },
  { cat: 5, q: "Kaj storimo s stvarmi, ki jih najdemo v obalnem morju?", a: "Stvari, najdene v obalnem morju, moramo prijaviti pristojnemu organu oziroma jih izročiti po pravilih o najdenih stvareh. Ne smemo si jih samovoljno prilastiti, posebej če gre za opremo, tovor ali predmete, povezane z nezgodo." },
  { cat: 5, q: "Kako delimo morje?", a: "Morje v pravnem smislu delimo na notranje morske vode, teritorialno morje, zunanji pas oziroma druge pasove, kjer jih država določa, in odprto morje. Za voditelja čolna sta posebej pomembna notranje morje in teritorialno morje, ker tam veljajo pravila obalne države." },
  { cat: 3, q: "Kakšno gorivo uporabljajo dizel motorji?", a: "Dizel motorji uporabljajo za gorivo plinsko olje (nafta).\nKakšno gorivo uporabljajo dvotaktni bencinski motorji?\nDvotaktni bencinski motorji uporabljajo za gorivo mešanico olja in bencina v razmerju, ki ga predpiše proizvajalec motorja." },
  { cat: 5, q: "Kje poteka temeljna črta teritorialnega morja?", a: "Temeljna črta teritorialnega morja poteka po črti nizke vode ob obali oziroma po ravnih temeljnih črtah, kjer so določene. Od nje se meri širina teritorialnega morja." },
  { cat: 1, q: "Na kaj moramo biti pozorni pri vremenski napovedi?", a: "Pri vremenski napovedi moramo biti posebej pozorni na opozorila o nevihtah, močnem vetru, nenadni spremembi vremena, zmanjšani vidljivosti, stanju morja in smeri ter jakosti vetra. Za majhna plovila so nevarni predvsem hitri prehodi front, burja, jugo, lebič in poletne nevihte." },
  { cat: 6, q: "Kdaj obstaja nevarnost trčenja dveh plovil pri križanju kurzev?", a: "Nevarnost trčenja pri križanju kurzev obstaja takrat, ko se premčev kot ali azimut, ki ga merimo v časovnih presledkih na drugo plovilo, bistveno ne spreminja." },
  { cat: 1, q: "Kje dobimo vremensko napoved?", a: "Vremensko napoved dobimo prek vremenskih služb, radijskih obvestil za pomorščake, spletnih in mobilnih vremenskih virov, pristaniških kapitanij, marin in oglasnih desk. Med plovbo spremljamo pomorska vremenska poročila na razpoložljivih radijskih kanalih oziroma napravah." },
  { cat: 3, q: "Kako delimo električne vžigalne svečke?", a: "Vžigalne svečke delimo po toplotni vrednosti in po obliki oziroma dolžini navoja. Uporabiti moramo svečko, ki jo predpiše proizvajalec motorja, ker napačna svečka lahko povzroči slabo delovanje ali poškodbe motorja." },
  { cat: 5, q: "Kaj obsega nadzor nad varnostjo plovbe glede čolnov?", a: "Nadzor obsega preverjanje listin, usposobljenosti voditelja, opreme, označbe čolna, sposobnosti čolna za plovbo, spoštovanja omejitev plovbe, pravil v pristaniščih in pravil o varnosti plovbe." },
  { cat: 2, q: "Kaj je čoln?", a: "Čoln je plovilo, ki meri v dolžino do 24 m. V to skupino spadajo različna manjša plovila glede na obliko, pogon, namen in material gradnje." },
  { cat: 5, q: "Kaj obsega carinsko območje?", a: "Carinsko območje na morju obsega območje, na katerem lahko pristojni organi izvajajo carinski nadzor nad blagom, osebami in plovili. Pri prehodu državne meje se mora voditelj čolna prijaviti na uradnem mejnem oziroma carinskem mestu in predložiti predpisane listine." },
  { cat: 3, q: "Kako deluje podmazovanje pri sodobnejših dvotaktnih motorjih?", a: "Pri sodobnejših dvotaktnih motorjih je olje v ločenem rezervoarju. Posebna naprava ga glede na obrate in obremenitev motorja odmerja ter primeša gorivu oziroma zraku, zato motor dobi ravno toliko olja, kot ga potrebuje za podmazovanje." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da imamo namen prehitevati drugo plovilo po levi?", a: "Dva dolga in dva kratka piska pomenijo, da nameravamo v ožini ali kanalu prehitevati po levi strani drugega plovila." },
  { cat: 4, q: "Kaj je oznaka varnih voda IALA?", a: "Oznaka varnih voda pomeni, da so vode okoli oznake plovne in brez posebne navigacijske nevarnosti. Oznaka je rdeče-bela z navpičnimi progami. Lahko označuje sredino plovne poti, varno območje ali pristop k pristanišču. Če ima luč, je ta bele barve." },
  { cat: 5, q: "Koliko smejo plavati kopalci od obale?", a: "Kopalci smejo praviloma plavati do 150 m od obale, če ni s predpisi ali lokalnimi označbami določeno drugače. Plovila morajo pri plovbi ob kopališčih upoštevati predpisane varnostne razdalje." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je ladja na mehanični pogon na plovni poti in se ne premika?", a: "Dva dolga zvoka v presledku 2 sekund in intervalu ne več kot 2 minute." },
  { cat: 5, q: "Koliko je široko teritorialno morje?", a: "Teritorialno morje je široko do 12 navtičnih milj od temeljne črte. Zunanji rob teritorialnega morja je hkrati zunanja meja območja, kjer obalna država izvaja svojo suverenost po pravilih mednarodnega prava." },
  { cat: 1, q: "Kaj je burja?", a: "Burja je suh, hladen in sunkovit veter, ki najpogosteje piha iz severovzhodne smeri, lahko pa tudi iz širšega območja med severom in vzhodom. Nastane zaradi razlik v zračnem tlaku in zaradi spuščanja hladnega zraka s kopnega proti morju. Ustvarja kratke, strme in nevarne valove ter je za majhna plovila zelo nevarna, ker se lahko pojavi hitro in v močnih sunkih." },
  { cat: 2, q: "Kaj je pomembno pri sidranju?", a: "Pri sidranju izberemo primerno mesto glede na globino, vrsto dna, zavetje pred vetrom, valovi in tokom ter razdaljo do drugih plovil in obale. Uporabimo primerno sidro, dovolj dolgo sidrno vrv ali verigo in preverimo, ali sidro drži." },
  { cat: 3, q: "Kako delimo motorje glede na vgradnjo v čoln?", a: "Glede na vgradnjo motorje delimo na vgrajene motorje, izvenkrmne oziroma krmne motorje in motorje z Z-pogonom. Razlikujejo se po namestitvi, dostopnosti za vzdrževanje, manevrskih lastnostih in izkoristku pogona." },
  { cat: 3, q: "Kako deluje podmazovanje pri štiritaktnih motorjih?", a: "Pri štiritaktnih motorjih olje kroži ločeno od goriva. Oljna črpalka črpa olje iz oljnega korita in ga pod tlakom pošilja do mazalnih mest. Olje zmanjšuje trenje, hladi dele motorja in se nato vrača v oljno korito." },
  { cat: 5, q: "Kje mora biti na čolnu označba in ime ter kakšne barve?", a: "Označba čolna mora biti na obeh straneh premca. Ime čolna, če ga ima, je običajno na krmi ali na bokih krme. Črke in številke morajo biti v barvi, ki se jasno loči od barve trupa, da so dobro vidne." },
  { cat: 5, q: "Kje se moramo pri prehodu državne meje s čolnom prijaviti in katere listine je treba predložiti organom na mejnem prehodu?", a: "Pri prehodu državne meje se moramo prijaviti v pristanišču oziroma na mejnem prehodu, kjer je dovoljen mednarodni pomorski promet. Predložimo osebne dokumente posadke, vpisni list plovila, zavarovalno polico, dokazilo o usposobljenosti za upravljanje čolna in po potrebi potrdilo za uporabo pomorske radijske postaje." },
  { cat: 6, q: "Kateri zvočni signal pomeni »zavijam levo«?", a: "Dva kratka piska pomenita: »Zavijam levo.«" },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi z vetrom v pol krme?", a: "Pri vetru v pol krme čoln sili s premcem proti vetru in se lahko želi postaviti bočno na veter in valove. Slabše drži smer, zato mora krmar natančneje popravljati smer in paziti na valove od zadaj oziroma s strani." },
  { cat: 3, q: "Kaj storimo, če nam izvenkrmni motor pade v morje?", a: "Motor čim prej dvignemo iz morja, ga speremo s sladko vodo, posušimo električno napeljavo, jo zaščitimo s primernim sredstvom in motor čim prej damo strokovno pregledati oziroma zagnati po navodilih. Izvenkrmni motor je priporočljivo dodatno zavarovati s krajšo vrvjo, da ne pade v vodo." },
  { cat: 4, q: "Kako določimo položaj z dvema azimutoma?", a: "V čim krajšem časovnem razmiku izmerimo azimuta na dva različna, dobro vidna in na karti vrisana objekta. Kompasna azimuta popravimo v prava azimuta z upoštevanjem skupnega popravka, ju vrišemo na karto, presečišče obeh azimutnih linij pa je položaj plovila. Najboljši je kot med azimutoma okoli 90°." },
  { cat: 5, q: "Kakšen je režim plovbe v teritorialnih vodah?", a: "V teritorialnem morju tuje države velja pravica neškodljivega prehoda, če plovilo pluje neprekinjeno in hitro ter ne ogroža miru, reda ali varnosti obalne države. Upoštevati je treba predpise obalne države." },
  { cat: 2, q: "Kako ravnamo pri vdoru vode?", a: "Najprej ugotovimo vzrok in mesto vdora vode. Takoj začnemo omejevati ali zapirati odprtino s čepi, ponjavo, blazinami, deskami, hitroveznim cementom ali drugimi pripomočki ter hkrati izčrpavamo vodo. Posadki po potrebi razdelimo rešilne jopiče. Če vdora ne moremo ustaviti, čoln usmerimo proti najbližji varni obali ali plitvini in skušamo nadzorovano nasesti." },
  { cat: 2, q: "Kako moramo pluti mimo zasidranih čolnov ob naravni plaži?", a: "Mimo zasidranih čolnov ob naravni plaži plujemo počasi, previdno in na taki razdalji, da z valovi ne ogrožamo ljudi, plovil ali kopalcev. Hitrost zmanjšamo na minimum, ki še omogoča varno upravljanje." },
  { cat: 4, q: "Kaj je magnetni kompas?", a: "Magnetni kompas je navigacijski instrument, ki kaže smer magnetnega meridiana. Uporabljamo ga za določanje kurza in azimuta, pri tem pa moramo upoštevati varijacijo in devijacijo." },
  { cat: 1, q: "Kaj je tramontana?", a: "Tramontana je severni veter prehodnega značaja. Piha iz smeri severa, lahko se pojavi v vseh letnih časih, pogosto je kratkotrajna, lahko pa je močna in nevarna. Pogosto preide v burjo." },
  { cat: 2, q: "Katere oblike čolnov poznamo?", a: "Po obliki poznamo spodrivne oziroma deplasmanske čolne, polspodrivne čolne in drsne čolne oziroma gliserje. Po številu trupov poznamo enotrupne čolne, katamarane in trimarane." },
  { cat: 5, q: "Katera je predpisana oprema in območje plovbe za čoln s kabino nad 7 m dolžine?", a: "Čoln s kabino nad 7 m dolžine mora imeti predpisano opremo glede na območje plovbe, namen uporabe in število oseb. Poleg osnovne opreme praviloma potrebuje ustrezna rešilna sredstva, sidrno opremo, sredstva za gašenje, signalna sredstva, navigacijske luči, opremo za izčrpavanje vode, dokumentacijo in dodatno opremo, predpisano za širše območje plovbe." },
  { cat: 5, q: "Koliko najmanj mora od obale pluti čoln, ki glisira?", a: "Čoln, ki glisira, mora pluti najmanj 250 m od obale, razen v posebej označenih območjih vplutja ali izplutja oziroma kadar predpisi določajo drugače." },
  { cat: 1, q: "Kaj je burin?", a: "Burin je priobalni nočni veter, ki nastane, ker se kopno po sončnem zahodu ohlaja hitreje kot morje. Piha s kopnega proti morju, običajno iz smeri NNE do ENE, od večera do jutra." },
  { cat: 2, q: "Kakšne vrste vrvi poznamo?", a: "Vrvi delimo po materialu na kovinske vrvi, vrvi iz naravnih vlaken in vrvi iz umetnih vlaken. V navtiki se najpogosteje uporabljajo vrvi iz umetnih vlaken, ker so čvrste, elastične in odporne proti vlagi." },
  { cat: 2, q: "Kaj obsega vzdrževanje čolna?", a: "Vzdrževanje čolna obsega čiščenje in pranje po uporabi, pregled trupa in opreme, redno barvanje oziroma zaščito dna z antivegetativno barvo, menjavo cinkovih protektorjev, vzdrževanje vrvi in opreme ter redni servis motorja. Obseg je odvisen od materiala čolna in načina uporabe." },
  { cat: 4, q: "Kakšno karto uporabljamo pri navigaciji?", a: "Pri navigaciji uporabljamo pomorsko karto v Merkatorjevi projekciji. Na njej so smeri in koti prikazani uporabno za navigacijo, kurzna linija je ravna črta, razdalje pa merimo na merilu geografske širine." },
  { cat: 2, q: "Zakaj uporabljamo vrvi?", a: "Vrvi uporabljamo za privez plovila, sidranje, vleko, dvigovanje in spuščanje tovora, privez bokobranov, jadranje, ribištvo in različna druga mornarska opravila." },
  { cat: 6, q: "Katero od plovil na motorni pogon se je dolžno izogibati v primeru križanja kurzev?", a: "Izogiba se tisto motorno plovilo, ki vidi drugo plovilo preko svojega desnega boka, razen, če gre za plovilo, ki je nesposobno za manevriranje, ki ima omejeno sposobnost za manevriranje, če je jadrnica oz. če je zaposleno z ribolovom." },
  { cat: 4, q: "Kaj je skupni popravek (ps)?", a: "Skupni popravek je algebraična vsota varijacije in devijacije. Uporablja se pri pretvarjanju pravih, magnetnih in kompasnih kurzov oziroma azimutov. Zapišemo ga kot ps = varijacija + devijacija, pri čemer upoštevamo predznake vzhodnih in zahodnih vrednosti." },
  { cat: 1, q: "Kaj predstavlja kumulonimbus?", a: "Kumulonimbus je velik nevihtni oblak vertikalnega razvoja, pogosto z vrhom v obliki nakovala. Spremljajo ga močne padavine, sunki vetra, bliskanje, grmenje, lahko tudi toča in nevarne nenadne spremembe vremena." },
  { cat: 3, q: "Kako deluje podmazovanje pri dvotaktnem bencinskem (OTTO) motorju?", a: "Pri klasičnem dvotaktnem bencinskem motorju se olje primeša bencinu v razmerju, ki ga predpiše proizvajalec. Mešanica goriva in olja poganja motor in hkrati podmazuje njegove notranje dele." },
  { cat: 2, q: "Kako ravnamo, če nam oseba med plovbo pade v vodo?", a: "Takoj glasno opozorimo posadko, ohranimo vidni stik z osebo, zmanjšamo hitrost in obrnemo čoln na stran padca, da krmo in propeler oddaljimo od osebe. V vodo vržemo rešilni obroč ali drugo plavajoče sredstvo, se osebi približamo počasi in praviloma z zavetrne strani ter jo dvignemo v čoln. Po potrebi nudimo prvo pomoč." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je pilotski čoln med pilotažo?", a: "Pilotski čoln med pilotažo lahko poleg običajnih signalov oddaja štiri kratke piske, s katerimi opozori na svojo posebno vlogo." },
  { cat: 2, q: "Katera protipožarna sredstva poznamo?", a: "Protipožarna sredstva na plovilu so ročni gasilni aparati na prah, peno ali CO₂, vodna črpalka, pesek, požarna odeja oziroma ponjava in druga prekrivala. Pri tekočih gorivih ne uporabljamo vode kot glavnega sredstva, ampak prah, peno ali CO₂." },
  { cat: 4, q: "Kako delimo pomorske karte?", a: "Pomorske karte delimo na informativne, navigacijske in pomožne karte. Navigacijske karte so namenjene neposrednemu vodenju plovbe, informativne pa prikazujejo dodatne meteorološke, hidrološke ali druge podatke." },
  { cat: 2, q: "Kakšna sredstva lahko uporabimo za zaustavitev vdora vode v čoln?", a: "Za zaustavitev vdora vode lahko uporabimo čepe, ponjavo, odeje, blazine, deske, vzglavnike, hitrovezni cement, objemke in druge priročne materiale. Če je mogoče, luknjo tesnimo z zunanje strani, ker pritisk vode material pritiska ob trup." },
  { cat: 5, q: "Ali ima reševalec pri reševanju stvari pravico do nagrade?", a: "Pri reševanju stvari ima reševalec praviloma pravico do primerne nagrade, če je bilo reševanje uspešno in v skladu s predpisi. Pri reševanju ljudi pa je dolžnost pomagati neodvisna od nagrade." },
  { cat: 6, q: "Kaj pomeni zvočni signal iz petih kratkih piskov?", a: "Pet kratkih piskov pomeni opozorilni signal oziroma signal za vzbujanje pozornosti. Uporabimo ga, kadar ne razumemo namere drugega plovila ali menimo, da njegovo ravnanje ni varno." },
  { cat: 4, q: "Zakaj je treba pretvarjati azimute in kurze?", a: "Kurze in azimute pretvarjamo zato, ker na karti delamo s pravimi smermi, kompas pa kaže kompasne oziroma magnetne smeri. Pri pretvarjanju upoštevamo varijacijo in devijacijo oziroma skupni popravek, da lahko varno primerjamo smer na karti s smerjo na kompasu." },
  { cat: 5, q: "Kateri so osnovni instrumenti za nadzorovanje delovanja motorja?", a: "Osnovni instrumenti so merilnik temperature hladilne tekočine, merilnik tlaka olja, voltmeter, ampermeter oziroma indikator polnjenja, merilnik obratov in merilnik goriva. Poleg instrumentov spremljamo tudi zvočne alarme in opozorilne lučke." },
  { cat: 2, q: "Kje in v kolikšnem času moramo prijaviti pomorsko nezgodo čolna?", a: "Pomorsko nezgodo je treba prijaviti pristojni upravi, izpostavi ali organu, pri katerem je čoln vpisan. Prijava mora biti dana takoj, v opravičenih primerih pa najpozneje v predpisanem roku, običajno v treh dneh." },
  { cat: 5, q: "Katere listine morajo biti med plovbo na čolnu, ki je krajši od 3 m in z motornim pogonom do 3,7 kW - čoln, ki ni vpisan v vpisnik čolnov (neregistriran čoln)?", a: "Upravljalec čolna mora imeti potrdilo o opravljenem preizkusu znanja, priporoča pa se, da ima pri sebi dokazilo o lastništvu (neregistriranega) čolna in motorja (npr. račun čolna in motorja).." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti dajejo plovila krajša od 12 m?", a: "Plovila, krajša od 12 m, morajo v slabi vidljivosti oddajati učinkovit zvočni signal v presledkih, ki niso daljši od dveh minut, če ne morejo uporabljati standardnih signalov za večja plovila." },
  { cat: 2, q: "Kaj moramo vedeti, če izbruhne požar?", a: "Vedeti moramo, kaj gori, kje je požar, katera gasilna sredstva so primerna in kako se požar širi glede na veter. Hitro zmanjšamo hitrost, postavimo požar v zavetrje, uporabimo ustrezno gasilno sredstvo in poskrbimo za varnost oseb." },
  { cat: 4, q: "Kako lahko v nočni plovbi ugotovimo, kateri svetilnik opazujemo?", a: "Svetilnik prepoznamo po približnem položaju, barvi luči, ritmu bliskov, periodi, višini in dometu. Podatke primerjamo s pomorsko karto ali seznamom svetilnikov. Ker imajo svetilniki različne karakteristike, jih lahko ponoči med seboj ločimo." },
  { cat: 4, q: "Kaj je kurz (K)?", a: "Kurz je kot med severnim delom meridiana in vzdolžnico plovila v smeri plovbe. Meri se od 0° do 360° v smeri urinega kazalca. Poznamo pravi, magnetni in kompasni kurz. Na karti rišemo pravi kurz." },
  { cat: 2, q: "Zakaj je treba čoln vzdrževati?", a: "Čoln je treba vzdrževati, ker je stalno izpostavljen vodi, soli, soncu, vetru, mehanskim obremenitvam in obraščanju podvodnega dela. Slabo vzdrževanje zmanjšuje varnost, hitrost in zanesljivost ter povečuje porabo goriva." },
  { cat: 3, q: "Katere so dobre in slabe lastnosti krmnih motorjev?", a: "Dobre lastnosti izvenkrmnih oziroma krmnih motorjev so dobra dostopnost za servis, možnost snemanja, majhna poraba prostora v čolnu, dobre manevrske sposobnosti in možnost dviga noge v plitvi vodi. Slabe lastnosti so večja izpostavljenost zunanjim vplivom, obremenitev krme in vpliv na stabilnost manjših čolnov." },
  { cat: 3, q: "Kako deluje štiritaktni dizel motor, naštej takte?", a: "PRVI TAKT - je sesalni, bat s pomikom navzdol sesa sveži zrak v valj.\nDRUGI TAKT - je kompresijski, bat se pomika navzgor in zrak komprimira (stiska).\nTRETJI TAKT - je ekspanzija (delo), nastane po samovžigu goriva, ki je bilo vbrizgano\npod visokim tlakom v izgorevalni prostor nad valjem motorja, pri tem potisne bat navzdol in opravi delo. ČETRTI TAKT - je izpušni, bat iztisne ostanke izgorelih plinov v izpušni sistem." },
  { cat: 5, q: "Kje poteka državna meja?", a: "Državna meja na morju poteka po zunanjem robu teritorialnega morja, če ni z mednarodnimi sporazumi ali posebnimi pravili določeno drugače." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da se strinjamo z namero drugega plovila za prehitevanje?", a: "En dolg, en kratek, en dolg in en kratek pisk pomenijo, da se strinjamo z namero drugega plovila za prehitevanje v ožini ali kanalu." },
  { cat: 4, q: "Kakšne naloge rešujemo na navigacijski karti?", a: "Na navigacijski karti določamo in vrisujemo položaje, beremo geografske koordinate, rišemo kurze in azimute, merimo razdalje, prepoznavamo globine, oznake, nevarnosti, svetilnike in druge objekte ter načrtujemo varno plovno pot." },
  { cat: 4, q: "Kaj so geografske koordinate?", a: "Geografske koordinate so geografska širina in geografska dolžina. Geografska širina se meri od ekvatorja proti severu ali jugu do 90°, geografska dolžina pa od začetnega meridiana v Greenwichu proti vzhodu ali zahodu do 180°." },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi z bočnim vetrom?", a: "Pri bočnem vetru se čoln močno ziblje, zanaša ga vstran, valovi pa ga lahko obračajo ali naplavijo. Takšna plovba je lahko neudobna in nevarna, zato je treba zmanjšati hitrost in paziti na smer valov." },
  { cat: 3, q: "Kakšno gorivo uporabljajo štiritaktni bencinski motorji?", a: "Štiritaktni bencinski motorji uporabljajo bencin predpisane oktanske vrednosti. Olje ni primešano gorivu, ampak je v ločenem mazalnem sistemu motorja." },
  { cat: 2, q: "Kaj so lahko vzroki za vdor vode v čoln?", a: "Vzroki za vdor vode so lahko trčenje, nasedanje, udarec ob obalo, poškodba trupa zaradi slabega morja, popustitev cevi ali tesnil pri vsisu morske vode, slabo zaprti ventili, poškodovana oprema ali nepravilno vzdrževanje." },
  { cat: 3, q: "Kateri motorji uporabljajo električno vžigalno svečko?", a: "Električno vžigalno svečko uporabljajo bencinski oziroma OTTO motorji, ker se zmes bencina in zraka vžge z električno iskro. Dizelski motorji delujejo na samovžig goriva v stisnjenem vročem zraku." },
  { cat: 3, q: "Kako deluje štiritaktni bencinski (OTTO) motor, naštej takte?", a: "Štiritaktni bencinski motor deluje v štirih taktih: sesalni takt, ko v valj vstopi zmes zraka in bencina; kompresijski takt, ko bat zmes stisne; delovni takt, ko iskra svečke vžge zmes in potisne bat navzdol; ter izpušni takt, ko bat iztisne izgorele pline." },
  { cat: 4, q: "Kako plujemo v megli?", a: "V megli praviloma ne izplujemo, če to ni nujno. Če že plujemo, zmanjšamo hitrost, poostrimo opazovanje in poslušanje, uporabljamo predpisane zvočne signale, spremljamo položaj na karti oziroma GPS-u in pazimo na nevarnost nasedanja ali trčenja." },
  { cat: 6, q: "Katere luči označujejo plovila na mehanski pogon in v katerih kotih so vidne?", a: "Plovilo na mehanski pogon med plovbo kaže belo jamborno luč, vidno v loku 225° po premcu; rdečo levo in zeleno desno bočno luč, vsako vidno v loku 112,5°; ter belo krmno luč, vidno v loku 135°. Ladje daljše od 50 m imajo še drugo belo jamborno luč, postavljeno višje in bolj proti krmi." },
  { cat: 5, q: "Kakšen je režim plovbe v tuje notranje morske vode?", a: "Za vplutje v tuje notranje morske vode je treba upoštevati predpise države gostiteljice, opraviti mejne in carinske formalnosti, izobesiti predpisane zastave in imeti urejene listine plovila ter posadke. Notranje morske vode niso območje prostega neškodljivega prehoda v enakem smislu kot teritorialno morje." },
  { cat: 5, q: "Katere listine je treba priložiti k vlogi za vpis morskega čolna?", a: "K vlogi za prvi vpis čolna se priložijo dokazilo o lastništvu, listine o tehničnih podatkih in skladnosti čolna oziroma motorja, dokazilo o zavarovanju, kadar je predpisano, dokazila o identiteti lastnika ter druge listine, ki jih zahteva pristojni organ glede na vrsto čolna in namen uporabe." },
  { cat: 4, q: "Kaj so znaki in kratice na pomorskih kartah?", a: "Znaki in kratice na pomorskih kartah so standardizirane oznake za globine, vrsto dna, nevarnosti, svetilnike, boje, kable, cevovode, pristanišča in druge navigacijsko pomembne podatke. Njihov pomen je razložen v kartografskem ključu znakov in krajšav." },
  { cat: 2, q: "Kaj je stabilnost čolna?", a: "Stabilnost čolna je sposobnost plovila, da se upira nagibanju zaradi vetra, valov, premikanja oseb ali tovora in da se po prenehanju teh vplivov vrne v ravnotežni položaj. Dobra stabilnost je bistvena za varno plovbo." },
  { cat: 2, q: "Kaj pomeni, da sidro \"orje\" in kaj storiti v tem primeru?", a: "Če sidro orje, pomeni, da se ni dobro zarilo v dno in drsi po morskem dnu. V tem primeru ponovno sidramo, spustimo več sidrne vrvi ali verige, izberemo primernejše sidro ali drugo mesto z boljšim dnom. Če sidro še vedno ne drži, sidranje ni varno." },
  { cat: 4, q: "Kako uporabljamo radar pri obalni navigaciji?", a: "Radar uporabljamo za določanje položaja, merjenje razdalj do obale ali objektov, zaznavanje drugih plovil in pomoč pri plovbi v zmanjšani vidljivosti, na primer v megli, dežju ali ponoči. Radar je pomožno sredstvo in ne nadomesti opazovanja, karte in varne hitrosti." },
  { cat: 4, q: "Branje pomorske karte.", a: "Kandidatu se pokažejo določeni znaki in kratice na karti (npr. znak za čeri, izobato, vrsta morskega dna, ipd) katerih pomen mora obrazložiti. Znaki in kratice so prikazani v publikaciji »Kartografski ključ znakov in krajšav«." },
  { cat: 2, q: "Kako ravnamo pri nasedanju čolna?", a: "Najprej preverimo, ali je trup poškodovan in ali vdira voda. Ugotovimo vrsto dna in del čolna, ki je nasedel. Če ni vdora vode, poskušamo čoln previdno rešiti z lastnim pogonom, sidrom, vleko drugega plovila, premikom tovora ali počakamo na višjo vodo. Če voda vdira, najprej omejimo vdor in izčrpavamo vodo, nato rešujemo plovilo." },
  { cat: 2, q: "Kako ravnamo, če se med plovbo pojavi požar na čolnu?", a: "Zmanjšamo hitrost, čoln obrnemo tako, da je požar v zavetrju, poskrbimo za varnost oseb in uporabimo ustrezna gasilna sredstva. Če požara ne moremo pogasiti, se lahko odločimo za nasedanje ali zapustitev čolna, pri čemer najprej rešujemo ljudi." },
  { cat: 4, q: "Kako odčitamo koordinate danega položaja na karti?", a: "Geografsko širino odčitamo na levem ali desnem robu karte, geografsko dolžino pa na zgornjem ali spodnjem robu karte. Iz danega položaja prenesemo razdaljo do ustreznega roba s šestilom ali vzporednicami in odčitamo stopinje ter minute." },
  { cat: 5, q: "Na kakšni dovoljeni minimalni razdalji sme čoln pluti od zunanjega roba označenega kopališča?", a: "Čoln mora pluti zunaj označenega kopališča in na predpisani varnostni razdalji od njegovega zunanjega roba. V praksi mora voditelj čolna upoštevati lokalne označbe in pluti tako, da ne ogroža kopalcev." },
  { cat: 3, q: "Kaj je narobe, če motor ne drži minimalnih obratov?", a: "Če motor ne drži minimalnih obratov, je lahko slabo nastavljen prosti tek, zamašena šoba v uplinjaču, umazan filter, nepravilna zmes goriva in zraka, neustrezna svečka ali moten dovod goriva." },
  { cat: 3, q: "Kolikokrat se obrne ročična gred, ko motor opravi delovni takt?", a: "Pri dvotaktnem motorju se ročična gred za en delovni cikel obrne enkrat. Pri štiritaktnem motorju se za en delovni cikel obrne dvakrat." },
  { cat: 2, q: "Kaj so lahko vzroki nasedanja čolna?", a: "Vzroki nasedanja so lahko nepravilna plovba, nepoznavanje globin, neupoštevanje karte, okvara motorja ali krmila, veter, tok, zmanjšana vidljivost, malomarnost posadke ali višja sila." },
  { cat: 1, q: "Kako določimo smer vetra?", a: "Smer vetra določimo po smeri, iz katere veter piha. Severni veter na primer piha s severa proti jugu." },
  { cat: 1, q: "Kako določimo moč vetra in stanje morja brez uporabe instrumentov?", a: "Moč vetra in stanje morja brez instrumentov ocenimo po Beaufortovi lestvici. Opazujemo videz morske gladine, višino in lomljenje valov, peno, pršenje vode in vpliv vetra na plovilo." },
  { cat: 3, q: "Zakaj je treba podmazovanje v motorju?", a: "Podmazovanje zmanjšuje trenje in obrabo gibljivih delov, odvaja toploto, pomaga pri tesnjenju in ščiti kovinske dele pred korozijo. Brez ustreznega podmazovanja lahko motor hitro zariba." },
  { cat: 3, q: "Kakšne sisteme vodno hlajenih motorjev poznamo?", a: "Poznamo odprti sistem vodnega hlajenja, pri katerem morska voda kroži skozi motor in se vrne v morje, ter zaprti sistem, pri katerem hladilna tekočina kroži v motorju, morska voda pa jo hladi prek izmenjevalnika toplote." },
  { cat: 2, q: "Kako poteka manever sidranja?", a: "Sidrišču se približamo počasi, preverimo globino, dno, veter in tok. Na izbrani točki zmanjšamo hitrost ali zapeljemo rahlo nazaj, spustimo sidro in dovolj vrvi oziroma verige, nato preverimo, ali sidro drži. Sidranja ne zaključimo, dokler nismo prepričani, da plovilo ne drsi." },
  { cat: 5, q: "Katero je območje plovbe in katere so omejitve glede plovbe vodnega skuterja?", a: "Vodni skuter sme pluti v območju, ki je od obale oddaljeno najmanj 250 m in največ 2000 m. Plovba je dovoljena samo podnevi oziroma od sončnega vzhoda do sončnega zahoda, v normalnih vremenskih razmerah in ob upoštevanju drugih lokalnih omejitev." },
  { cat: 3, q: "Kakšne so posledice neprimernega podmazovanja?", a: "Neprimerno podmazovanje povzroči povečano trenje, segrevanje, obrabo ležajev in batov, poškodbe drsnih površin, izgubo moči in v skrajnem primeru blokado oziroma zaribanje motorja." },
  { cat: 2, q: "Kakšna sredstva uporabljamo za gašenje tekočega goriva?", a: "Za gašenje tekočega goriva uporabljamo gasilne aparate na prah, peno ali CO₂. Vode praviloma ne uporabljamo, ker lahko gorivo razlije in požar razširi." },
  { cat: 3, q: "Katera naprava lahko nadomesti uplinjač?", a: "Uplinjač lahko nadomesti naprava za vbrizg goriva. Ta gorivo dozira natančneje, izboljša zagon, porabo in delovanje motorja v različnih režimih." },
  { cat: 3, q: "Na kakšne načine se podmazujejo motorji pri delovanju?", a: "Motorji se lahko podmazujejo z oljem v mešanici pri dvotaktnih motorjih, s tlačnim podmazovanjem pri štiritaktnih motorjih in z oplakovanjem oziroma razprševanjem olja v posameznih izvedbah motorjev." },
  { cat: 1, q: "Kaj je ponente?", a: "Ponente je zahodni veter. Na Jadranu je lahko prehoden ali nevihten veter iz smeri zahoda, zato lahko hitro poslabša razmere na morju, posebej na obalah, izpostavljenih zahodu." },
  { cat: 2, q: "Ali ima voditelj čolna za reševanje ljudi pravico do nagrade in ali je dolžan reševati ljudi na morju?", a: "Voditelj čolna je dolžan pomagati ljudem v nevarnosti na morju, če s tem resno ne ogrozi svojega plovila, posadke ali drugih oseb. Za reševanje ljudi praviloma ne gre za nagrado kot pri reševanju stvari; prednost ima dolžnost pomoči." },
  { cat: 4, q: "Kaj je azimut (ω)?", a: "Azimut je kot med severnim delom meridiana in smerjo od opazovalca proti opazovanemu objektu. Meri se od 0° do 360° v smeri urinega kazalca. Poznamo pravi, magnetni in kompasni azimut." },
  { cat: 2, q: "Naštejte nekaj načinov določanja položaja čolna na morju?", a: "Položaj čolna lahko določimo z dvema azimutoma na dva objekta, z dvema azimutoma na isti objekt v časovnem razmaku, s pokrito smerjo in azimutom, z radarskimi razdaljami, z merjenjem globine ob primerjavi s karto ali z GPS-om." },
  { cat: 6, q: "Kaj pomeni kratek in kaj dolg pisk?", a: "Kratek pisk traja približno 1 sekundo. Dolg pisk traja približno 4 do 6 sekund." },
  { cat: 2, q: "Katere vrste vrvi se najbolj uporabljajo in zakaj?", a: "Najpogosteje se uporabljajo vrvi iz umetnih vlaken, ker so čvrste, prožne, lahke, odporne proti vlagi in manj občutljive na gnitje kot vrvi iz naravnih vlaken." },
  { cat: 4, q: "Kaj je varijacija?", a: "Varijacija je kot med pravim in magnetnim meridianom. Nastane zaradi zemeljskega magnetizma, ker se geografski in magnetni poli ne pokrivajo. Podatek o varijaciji in njeni letni spremembi je naveden na pomorski karti, pogosto v roži vetrov." },
  { cat: 5, q: "Kdaj je treba opraviti redni pregled čolna?", a: "Redni pregled se opravlja v predpisanih časovnih presledkih glede na vrsto, namen uporabe, starost in tehnične značilnosti čolna. Namen rednega pregleda je preveriti, ali je čoln še vedno sposoben za varno plovbo." },
  { cat: 3, q: "Kako vzdržujemo akumulator?", a: "Akumulator vzdržujemo tako, da preverjamo napolnjenost, čistimo in zaščitimo kontakte, pazimo na pravilno pritrditev in prezračevanje ter preprečimo globoko izpraznitev. Pri klasičnih akumulatorjih po potrebi preverimo nivo elektrolita in dolijemo samo destilirano vodo." },
  { cat: 2, q: "Katere dolžine čolna poznamo?", a: "Poznamo dolžino čez vse, ki zajema največjo dolžino plovila, in dolžino na konstrukcijski vodni črti, ki je dolžina plovila na vodni liniji." },
  { cat: 1, q: "Kako vplivata morski tok in veter na plovbo?", a: "Morski tok in veter lahko povečata ali zmanjšata hitrost čolna ter ga zanašata iz načrtovane smeri. Če zanosa ne upoštevamo, ne bomo prispeli na načrtovano točko, zato moramo kurz ustrezno popraviti." },
  { cat: 1, q: "Kaj je hitrost vetra?", a: "Hitrost vetra je pot, ki jo zračna masa opravi v določeni časovni enoti. Izražamo jo v metrih na sekundo, kilometrih na uro ali vozlih." },
  { cat: 4, q: "Kaj je oznaka osamljene nevarnosti IALA?", a: "Oznaka osamljene nevarnosti označuje majhno nevarno območje, ki je obdano s plovno vodo. Nevarnost je pri oznaki, okoli nje pa je voda praviloma plovna. Oznaka ima črno barvo z enim ali več rdečimi vodoravnimi pasovi in vrhnje znamenje iz dveh črnih krogel." },
  { cat: 6, q: "Katere luči in znamenja so predpisane v pravilih o izogibanju trčenj na morju?", a: "Predpisane luči so jamborna luč, bočni luči, krmna luč, krožna luč, luč za vleko in bliskajoča luč. Barve so bela, rdeča, zelena in rumena. Dnevna znamenja so črne oblike, kot so krogla, stožec in valj, ter njihove kombinacije. Luči uporabljamo ponoči in pri zmanjšani vidljivosti, znamenja pa podnevi." },
  { cat: 3, q: "Katere so dobre lastnosti \"Z\" pogona?", a: "Z-pogon združuje prednosti vgrajenega in izvenkrmnega motorja. Motor je vgrajen v plovilo, pogonska noga z vijakom pa je gibljiva, zato ima plovilo dobre manevrske sposobnosti, boljši izkoristek in možnost dviga pogonskega dela v plitvejši vodi." },
  { cat: 5, q: "Kaj mora storiti oseba, ki upravlja čoln oziroma lastnik, v primeru izrednega dogodka?", a: "Ob izrednem dogodku, kot so trčenje, potopitev, požar ali hujša poškodba, mora upravljalec oziroma lastnik najprej poskrbeti za varnost ljudi, nato pa o dogodku takoj obvestiti pristojni organ oziroma izpostavo, kjer je čoln vpisan. V opravičenih primerih mora dogodek prijaviti najpozneje v predpisanem roku." },
  { cat: 3, q: "Kateri element v motorju skrbi, da bo temperatura hladilne tekočine konstantna?", a: "Za stalno delovno temperaturo hladilne tekočine skrbi termostat. Odpira in zapira pretok hladilne tekočine skozi hladilni sistem, da motor ne deluje ne prehladno ne prevroče." },
  { cat: 6, q: "Katere luči svetijo v krogu 360°?", a: "V krogu 360° svetijo krožne luči. Uporabljajo jih na primer zasidrana plovila, nekatera majhna plovila, ribiška plovila, plovila nesposobna za manevriranje, plovila z omejeno sposobnostjo manevriranja in druge posebne kategorije plovil glede na pravila." },
  { cat: 1, q: "Kako nastane veter?", a: "Veter nastane zaradi razlik v zračnem tlaku. Zračne mase se premikajo iz območja višjega zračnega tlaka proti območju nižjega zračnega tlaka. Na smer in hitrost vetra vplivajo tudi vrtenje Zemlje, relief, segrevanje kopnega in morja ter vremenski sistemi." },
  { cat: 2, q: "Kako se meri višina čolna?", a: "Višina čolna se meri od spodnjega roba gredlja do zgornjega roba palube oziroma robnice." },
  { cat: 4, q: "Kaj je navigacija?", a: "Navigacija je znanost in veščina varnega vodenja plovila od izhodišča do cilja. Vključuje določanje položaja, načrtovanje poti, branje kart, uporabo kompasa, oceno vremena, globin, nevarnosti in prometa." },
  { cat: 5, q: "Kdaj čoln glisira?", a: "Čoln glisira, ko zaradi hitrosti preide iz spodrivne plovbe v drsenje po vodni površini. Takrat se premec dvigne, večji del trupa se dvigne iz vode, upor se spremeni, hitrost pa se poveča." },
  { cat: 1, q: "Kaj je jugo?", a: "Jugo je topel in vlažen veter iz jugovzhodne smeri, pogosto povezan s ciklonom. Na Jadranu se razvija postopno, prinaša oblačno vreme, dež in dolge, večje valove. Čeprav je pogosto manj sunkovit kot burja, je lahko zaradi valov zelo naporen in nevaren." },
  { cat: 1, q: "S čim opišemo vreme?", a: "Vreme opišemo z vremenskimi pojavi, oblačnostjo, vetrom, temperaturo zraka, vlago, zračnim tlakom, vidljivostjo, padavinami in stanjem morja. Za plovbo so najpomembnejši veter, nevarnost neviht, vidljivost in valovi." },
  { cat: 4, q: "Kako izmerimo globino morja?", a: "Globino morja lahko izmerimo z vrvjo in utežjo ali z ultrazvočnim globinomerom. Podatek o globini je pomemben za varno plovbo, sidranje, izogibanje nasedanju in oceno položaja glede na izobate na karti." },
  { cat: 3, q: "Kaj je uplinjač?", a: "Uplinjač je naprava pri bencinskem motorju, ki pripravi primerno zmes zraka in bencina za izgorevanje. Pri novejših motorjih ga pogosto nadomešča elektronski vbrizg goriva." },
  { cat: 4, q: "Kaj je morski horizont in kako ga delimo?", a: "Morski horizont oziroma obzorje je navidezna črta, ki ločuje morje od neba in omejuje vidno polje opazovalca. Delimo ga na 360° ter na glavne in vmesne smeri: N, E, S, W, NE, SE, SW, NW in še natančnejše vmesne smeri." },
  { cat: 2, q: "Naštej nekaj vrst sider?", a: "Pogosta sidra so admiralitetno sidro, Danforth sidro, sidro goba, sidro maček, patentno oziroma dežnik sidro, plužno sidro in Hallovo sidro. Izbira sidra je odvisna od velikosti plovila in vrste morskega dna." },
  { cat: 2, q: "Naštej smeri glede na čoln, v katerih lahko vidimo drug objekt.", a: "Drug objekt lahko vidimo po premcu, levo po premcu, bočno levo, levo po krmi, po krmi, desno po krmi, bočno desno ali desno po premcu." },
  { cat: 3, q: "Kako deluje dvotaktni bencinski (OTTO) motor, naštej takte?", a: "Dvotaktni bencinski motor opravi delovni ciklus v dveh taktih. V prvem delu se zmes vžge, bat opravi delovni gib in hkrati omogoči izpuh ter vstop sveže zmesi. V drugem taktu bat stiska svežo zmes do zgornje mrtve točke, kjer jo vžge iskra svečke. Pri klasičnem dvotaktnem motorju olje običajno dodamo gorivu." },
  { cat: 1, q: "Kaj je lebič (garbin)?", a: "Lebič oziroma garbin je nevihtni jugozahodni veter. Spremljajo ga veliki valovi in močne padavine, posebej nevaren pa je za pristanišča in obale, ki niso zaščiteni pred jugozahodom. Poleti se lahko pojavi ob lokalnih nevihtah, v drugih letnih časih pa je pogosto povezan s prehodi ciklonov." },
  { cat: 5, q: "Katero opremo mora imeti upravljalec vodnega skuterja?", a: "Upravljalec vodnega skuterja mora imeti rešilni jopič in drugo predpisano osebno zaščitno opremo. Imeti mora tudi ustrezno usposobljenost oziroma dovoljenje, pri plovbi pa mora upoštevati območje, čas in vremenske omejitve." },
  { cat: 1, q: "Kaj je oštro?", a: "Oštro je južni veter. Je prehoden in običajno kratkotrajen veter iz smeri juga, ki lahko spremlja spremembe vremena." },
  { cat: 2, q: "Kako pristajamo bočno ob obalo?", a: "Pri bočnem pristajanju zmanjšamo hitrost, ocenimo veter in tok, pripravimo bokobrane, privezne vrvi in čolnarski kavelj. Obali se približamo pod kotom približno 30° do 45°. Ko smo dovolj blizu, prestavimo v prosti tek, po potrebi zavozimo nazaj, privežemo najprej premec in nato krmo ter z motorjem in krmilom popravimo položaj." },
  { cat: 2, q: "Zakaj je treba najprej privezati premec čolna?", a: "Pri bočnem pristajanju najprej privežemo premec, ker lahko krmo nato z motorjem in krmilom lažje približamo obali. Če bi najprej privezali krmo, bi lahko veter ali tok odnesel premec in otežil pristanek." },
  { cat: 2, q: "Kako izbiramo primerno sidro in sidrno vrv?", a: "Sidro izberemo glede na velikost in težo plovila, vrsto morskega dna, pričakovane vremenske razmere in globino. Sidrna vrv oziroma veriga mora biti dovolj močna in dolga; praviloma spustimo najmanj trikratnik globine, v slabših razmerah več. Veriga pri sidru izboljša kot vleka in pomaga, da sidro bolje drži." },
  { cat: 3, q: "Kaj je narobe, če nam motor pokašljuje, preden ugasne?", a: "Če motor pokašljuje in nato ugasne, je najpogostejši vzrok moten dovod goriva: premalo goriva, umazan filter, zamašena šoba, zaprt zračnik rezervoarja, prekinjena cev ali umazanija v sistemu goriva." },
  { cat: 3, q: "Katero je osnovno orodje, ki ga je priporočljivo imeti v plovilu?", a: "Na plovilu je priporočljivo imeti osnovno orodje za manjša popravila: izvijače, klešče, univerzalni ključ, ključ za svečke, natikalne in viličaste ključe pogostih mer, manjše kladivo, nož, izolirni trak, vezice in rezervne objemke." },
  { cat: 4, q: "Katere merske enote se uporabljajo pri navigaciji?", a: "Pri navigaciji razdaljo merimo v navtičnih miljah. Ena navtična milja meri 1852 m in na karti ustreza eni minuti geografske širine. Manjša enota je kabel, približno 185,2 m. Hitrost merimo v vozlih, pri čemer en vozel pomeni eno navtično miljo na uro." },
  { cat: 4, q: "Kako delimo navigacijske karte?", a: "Navigacijske karte delimo na generalne karte za velika območja, kurzne karte za plovbo med območji, obalne karte za plovbo ob obali in plane za manjša območja, kot so pristanišča, sidrišča in kanali." },
  { cat: 4, q: "Kaj so informativne karte?", a: "Informativne karte vsebujejo podatke, ki pomagajo pri načrtovanju in varnosti plovbe, na primer meteorološke in hidrološke podatke, morske tokove, značilnosti območij in druge splošne informacije." },
  { cat: 4, q: "Kako na karto vrišemo položaj, ki ga pokaže GPS?", a: "GPS poda geografsko širino in dolžino. Na robovih karte poiščemo ustrezno širino in dolžino, skozi njiju prenesemo pomožni črti in v presečišču označimo položaj. Pri tem pazimo na pravilno odčitavanje stopinj, minut in decimalnih minut." },
  { cat: 2, q: "Katera so območja plovbe čolnov?", a: "Območja plovbe čolnov so A - oceansko območje, B - odprto območje, C - obalno območje in D - območje zavetja. Vpisano območje plovbe določa, kako daleč in v kakšnih razmerah sme čoln pluti ter kakšno opremo mora imeti." },
  { cat: 5, q: "Kdaj sme čoln izpluti?", a: "Čoln sme izpluti, če je sposoben za plovbo, ima veljavne listine, predpisano opremo, ustrezno usposobljenega voditelja in če vremenske ter druge razmere omogočajo varno plovbo." },
  { cat: 5, q: "Kakšne so kazni za lažje prekrške?", a: "Za lažje pomorske prekrške so predvidene denarne kazni. Višina kazni je odvisna od vrste kršitve in veljavnih predpisov, zato je treba za točen znesek preveriti aktualni predpis oziroma odločitev pristojnega organa." },
  { cat: 5, q: "Katere listine mora pri sebi imeti upravljalec čolna med plovbo?", a: "Upravljalec mora imeti pri sebi veljaven vpisni list oziroma listine čolna, dokazilo o zavarovanju, kadar je predpisano, osebni dokument in dokazilo o usposobljenosti za upravljanje čolna." },
  { cat: 2, q: "Katere so dolžnosti voditelja čolna pri upravljanju s čolnom?", a: "Voditelj čolna mora stalno opazovati okolico z vidom in sluhom, spremljati promet, vreme, globino in položaj plovila, pluti z varno hitrostjo, spoštovati predpise in pravočasno ukrepati za preprečitev trčenja ali druge nevarnosti." },
  { cat: 2, q: "Ali je pri vdoru vode bolje luknjo zapirati od zunaj ali od znotraj in zakaj?", a: "Če je izvedljivo, je bolje luknjo zapirati z zunanje strani, ker pritisk vode ponjavo, čep ali drug tesnilni material pritiska ob trup čolna. Če luknjo zapiramo z notranje strani, voda material potiska stran od odprtine, zato ga moramo dodatno podpreti ali zagozditi." },
  { cat: 6, q: "Kako prepoznamo najpogostejše nočne luči plovil?", a: "Nočne luči prepoznamo po barvi, položaju in kotu vidnosti. Motorno plovilo v plovbi kaže belo jamborno luč, rdečo levo bočno luč, zeleno desno bočno luč in belo krmno luč. Jadrnica v plovbi kaže rdečo in zeleno bočno luč ter belo krmno luč. Zasidrano plovilo kaže belo krožno luč. Plovilo nesposobno za manevriranje kaže dve rdeči krožni luči, plovilo z omejeno sposobnostjo manevriranja pa rdečo, belo in rdečo krožno luč navpično." },
  { cat: 6, q: "Kako prepoznamo najpogostejša dnevna znamenja plovil?", a: "Dnevna znamenja so črne oblike, ki se uporabljajo podnevi. Zasidrano plovilo kaže eno črno kroglo. Plovilo nesposobno za manevriranje kaže dve črni krogli navpično. Plovilo z omejeno sposobnostjo manevriranja kaže kroglo, dvojni stožec oziroma romb in kroglo. Plovilo omejeno z ugrezom kaže črn valj. Jadrnica, ki pluje tudi z motorjem, kaže črn stožec z vrhom navzdol. Ribiško plovilo kaže dva stožca z vrhovoma skupaj." },
  { cat: 6, q: "Kako se izogibata dve motorni plovili pri čelnem srečanju?", a: "Pri čelnem srečanju dveh motornih plovil, kadar obstaja nevarnost trčenja, morata obe plovili spremeniti smer v desno, tako da se srečata z levima bokoma. Manever mora biti pravočasen, odločen in dovolj očiten." },
  { cat: 6, q: "Kako se izogibata dve jadrnici?", a: "Če imata jadrnici veter z različnih strani, se izogiba jadrnica, ki ima veter z leve strani. Če imata veter z iste strani, se izogiba privetrna jadrnica. Če jadrnica z vetrom z leve strani vidi drugo jadrnico privetrno in ne more zanesljivo ugotoviti, s katere strani ima druga jadrnica veter, se mora izogibati." },
  { cat: 5, q: "Pod kaj spada vodni skuter?", a: "Vodni skuter je osebno plovilo na motorni pogon oziroma posebno plovilo za šport in razvedrilo. Pri izpitnih vprašanjih se obravnava ločeno, ker ima posebne omejitve plovbe in ker mora imeti upravljalec predpisano opremo, predvsem rešilni jopič." },
  { cat: 4, q: "Pri južni kardinalni oznaki, po kateri strani oznake je varna voda?", a: "Pri južni kardinalni oznaki je varna oziroma najgloblja voda južno od oznake. Zato plujemo južno od oznake oziroma se nevarnosti izognemo po južni strani. Vrhnje znamenje južne kardinalne oznake sta dva črna stožca z vrhovoma navzdol." },
  { cat: 4, q: "Kako preberemo karakteristiko svetilnika, na primer B Bl (2) 5s 16 m 6M?", a: "B pomeni bela luč. Bl (2) pomeni skupino dveh bliskov. 5s pomeni, da celoten cikel traja 5 sekund. 16 m pomeni, da je luč 16 m nad morsko gladino. 6M pomeni, da je domet luči 6 navtičnih milj. Celoten opis pomeni: bela luč, dva bliska v skupini vsakih 5 sekund, višina luči 16 m, domet 6 M." },
  { cat: 4, q: "Kaj pomeni oznaka podvodni kabel na pomorski karti?", a: "Oznaka podvodni kabel pomeni, da je na morskem dnu položen kabel. Na tem območju ne sidramo, ne vlečemo sidra in ne izvajamo dejanj, ki bi lahko poškodovala kabel. Pri plovbi moramo biti na takšno oznako posebej pozorni predvsem pri sidranju." },
  { cat: 4, q: "Kako rešimo navigacijsko nalogo, če je iz svetilnika podan azimut 310° in razdalja 2 M?", a: "Na karti najprej poiščemo dani svetilnik. Iz svetilnika narišemo smer 310°, kar je smer proti severozahodu. Na tej smeri odmerimo 2 navtični milji; razdaljo odmerimo na merilu geografske širine, ker 1 minuta širine pomeni 1 navtično miljo. Dobljena točka je položaj čolna. Pomembno je razlikovati, ali je podan azimut iz svetilnika ali azimut svetilnika iz čolna; v drugem primeru bi uporabili nasprotni azimut." },
  { cat: 6, q: "Kaj pomeni varna hitrost in kakšen mora biti manever izogibanja?", a: "Varna hitrost je taka hitrost, pri kateri lahko plovilo glede na vidljivost, gostoto prometa, manevrske lastnosti, veter, valove, tok, bližino obale in druge nevarnosti pravočasno ukrepa in se po potrebi ustavi na varni razdalji. Manever izogibanja mora biti pravočasen, odločen, dovolj velik in drugemu plovilu jasno viden." },
  { cat: 6, q: "Kdaj se šteje, da plovilo prehiteva drugo plovilo?", a: "Plovilo prehiteva, kadar se drugemu plovilu približuje iz smeri več kot 22,5° za njegovim bokom, torej iz območja krmne luči. Plovilo, ki prehiteva, se mora vedno izogibati prehitevanemu plovilu, dokler prehitevanja varno ne zaključi." },
  { cat: 6, q: "Kakšni so zvočni signali pri prehitevanju v ožinah ali kanalih?", a: "Če nameravamo prehitevati po desni, oddamo dva dolga in en kratek pisk. Če nameravamo prehitevati po levi, oddamo dva dolga in dva kratka piska. Če se drugo plovilo s prehitevanjem strinja, odgovori z enim dolgim, enim kratkim, enim dolgim in enim kratkim piskom." },
  { cat: 6, q: "Katerim plovilom se mora umakniti plovilo na mehanski pogon, kadar plove?", a: "Plovilo na mehanski pogon se mora praviloma umakniti plovilu, ki ni sposobno manevrirati, plovilu z omejeno sposobnostjo manevriranja, plovilu zaposlenemu z ribolovom in jadrnici, kadar ta pluje samo na jadra. Vedno pa ostaja splošna dolžnost ukrepati tako, da se prepreči trčenje." },
  { cat: 6, q: "Kakšne luči morajo imeti vlačilec, jadrnica, plovilo na vesla, ribiška ladja, plovilo nesposobno za manevriranje, plovilo z omejeno sposobnostjo manevriranja, plovilo omejeno z ugrezom, pilotska ladja, zasidrana ladja in nasukana ladja?", a: "Vlačilec poleg luči plovila na mehanski pogon kaže dodatne luči za vleko glede na vrsto in dolžino vleke. Jadrnica kaže bočni luči in krmno luč, plovilo na vesla pa najmanj belo luč ali svetilko za opozarjanje. Ribiška ladja kaže krožne luči glede na ribolov. Plovilo nesposobno za manevriranje kaže dve rdeči krožni luči, plovilo z omejeno sposobnostjo manevriranja rdečo-belo-rdečo krožno luč, plovilo omejeno z ugrezom tri rdeče krožne luči, pilotska ladja belo nad rdečo, zasidrana ladja belo krožno luč oziroma luči, nasukana ladja pa luči za sidranje in dodatno dve rdeči krožni luči." },
  { cat: 6, q: "Kakšni so osnovni zvočni signali za manevriranje, prehitevanje in zmanjšano vidljivost?", a: "En kratek pisk pomeni zavijam desno, dva kratka piska zavijam levo, trije kratki piski moji stroji delujejo nazaj, pet kratkih piskov pa opozorilo oziroma nerazumevanje namere drugega plovila. V ožinah dva dolga in en kratek pomenijo prehitevanje po desni, dva dolga in dva kratka prehitevanje po levi. V slabi vidljivosti ladja na mehanski pogon v plovbi oddaja en dolg zvok v presledkih do dveh minut." },
  { cat: 5, q: "Kje se v Republiki Sloveniji lahko vpiše čoln?", a: "Morski čoln se v Republiki Sloveniji vpiše pri Upravi Republike Slovenije za pomorstvo oziroma pri pristojni izpostavi. Pri vpisu se predložijo predpisane listine o čolnu, motorju, lastništvu, zavarovanju in usposobljenosti, če so zahtevane." },
  { cat: 2, q: "V kakšnem časovnem obdobju se opravljajo pregledi čolnov in za katere vrste čolnov?", a: "Časovni presledki rednih pregledov so odvisni od vrste čolna, njegove dolžine, namena uporabe, starosti, območja plovbe in pogona. Čolni za gospodarske ali javne namene in tehnično zahtevnejša plovila imajo praviloma strožje oziroma pogostejše preglede kot manjši čolni za osebno uporabo. Točne roke določa veljavni predpis oziroma vpisni list." },
  { cat: 5, q: "Kako se deli obalno morje?", a: "Obalno morje se deli predvsem na notranje morske vode in teritorialno morje. Notranje morske vode so med obalo in temeljno črto, teritorialno morje pa se meri od temeljne črte navzven do predpisane širine." },
  { cat: 5, q: "Od kod se meri teritorialno morje in kaj predstavlja njegov zunanji rob?", a: "Teritorialno morje se meri od temeljne črte teritorialnega morja proti odprtemu morju. Njegov zunanji rob predstavlja zunanjo mejo teritorialnega morja oziroma državno mejo na morju, če ni s posebnim dogovorom določeno drugače." },
  { cat: 5, q: "Kaj je carinski pas na morju?", a: "Carinski pas na morju je območje, v katerem lahko pristojni organi izvajajo carinski nadzor nad plovili, osebami in blagom. Namenjen je preprečevanju nedovoljenega vnosa ali iznosa blaga ter nadzoru prehoda meje." },
  { cat: 5, q: "Kakšne so obveznosti voditelja čolna pri plovbi v tujih notranjih morskih vodah in tujem teritorialnem morju?", a: "Voditelj mora upoštevati predpise države, v katere vode vpluje, opraviti mejne in carinske formalnosti, imeti urejene listine plovila in posadke ter izobesiti predpisane zastave. V teritorialnem morju lahko praviloma izvaja neškodljiv prehod, v notranje morske vode pa vpluje v skladu s pravili države gostiteljice." },
  { cat: 5, q: "Kakšna je predpisana minimalna oddaljenost plovbe od obale za različne vrste plovil?", a: "Motorni čoln, ki ne glisira, mora pluti najmanj 200 m od obale, čoln, ki glisira, najmanj 250 m, ladja najmanj 300 m, vodni skuter pa praviloma med 250 m in 2000 m od obale. Mimo kopališč, naravnih plaž in zasidranih plovil plujemo posebej previdno ter upoštevamo lokalne označbe." },
  { cat: 4, q: "Kje na pomorski karti odčitamo geografsko širino in kje geografsko dolžino?", a: "Geografsko širino odčitamo na levem ali desnem robu pomorske karte. Geografsko dolžino odčitamo na zgornjem ali spodnjem robu karte. Razdalje merimo na merilu geografske širine, ker ena minuta širine ustreza eni navtični milji." },
  { cat: 4, q: "Od kod se merita geografska širina in geografska dolžina ter koliko znašata največ?", a: "Geografska širina se meri od ekvatorja proti severu ali jugu do 90°. Geografska dolžina se meri od začetnega meridiana v Greenwichu proti vzhodu ali zahodu do 180°. Položaj na Zemlji določimo s kombinacijo širine in dolžine." },
  { cat: 4, q: "Kako rišemo in beremo kurz na pomorski karti?", a: "Kurz rišemo kot ravno kurzno linijo med izhodiščem in ciljem. S pomočjo navtičnih trikotnikov smer linije prenesemo na rožo vetrov oziroma meridiansko mrežo in odčitamo kot od severa v smeri urinega kazalca. Na karti beremo pravi kurz." },
  { cat: 4, q: "Katere osnove zemeljskega magnetizma so pomembne za navigacijo?", a: "Za navigacijo je pomembno, da magnetni kompas kaže magnetni sever, ki ni enak geografskemu severu. Razlika med pravim in magnetnim severom je varijacija, dodatno napako zaradi vplivov plovila pa imenujemo devijacija. Obe moramo upoštevati pri uporabi kompasa." },
  { cat: 4, q: "Kako preračunavamo kurze in azimute?", a: "Pri preračunavanju upoštevamo skupni popravek, ki je vsota varijacije in devijacije. Pri prehodu s pravega kurza ali azimuta na kompasnega skupni popravek odštevamo, pri prehodu s kompasnega na pravega pa ga prištevamo, ob pravilnem upoštevanju predznakov." },
  { cat: 4, q: "Kako določimo oddaljenost in prevoženo pot na pomorski karti?", a: "Oddaljenost na karti merimo s šestilom in jo odčitamo na merilu geografske širine ob robu karte. Ena minuta geografske širine pomeni eno navtično miljo. Prevoženo pot lahko izračunamo tudi iz hitrosti in časa: pot je hitrost v vozlih krat čas v urah." },
  { cat: 4, q: "Kako uporabljamo kompas pri plovbi?", a: "Kompas uporabljamo za držanje kurza in merjenje azimutov na objekte. Pri tem moramo upoštevati varijacijo, devijacijo in skupni popravek. Kompas mora biti nameščen stran od močnih magnetnih in električnih vplivov, voditelj pa mora redno preverjati, ali pluje po načrtovanem kurzu." },
  { cat: 3, q: "Kaj je magnetni vžig motorja?", a: "Magnetni vžig je sistem vžiga, pri katerem električno napetost za iskro ustvarja magnet oziroma magnetni generator. Pogost je pri manjših izvenkrmnih motorjih, ker za delovanje ne potrebuje nujno akumulatorja." },
  { cat: 3, q: "Kaj je baterijski vžig motorja?", a: "Baterijski vžig je sistem, pri katerem električno energijo za vžig zagotavlja akumulator. Sistem prek vžigalne tuljave ustvari visoko napetost, ki na svečki povzroči iskro in vžge zmes goriva in zraka." },
  { cat: 3, q: "Kako poteka dovod goriva pri bencinskem in dizelskem motorju?", a: "Pri bencinskem motorju gorivo iz rezervoarja potuje do uplinjača ali sistema vbrizga, kjer se pripravi zmes goriva in zraka. Pri dizelskem motorju črpalka dovaja gorivo pod visokim tlakom do šob, ki gorivo vbrizgajo v stisnjen in segret zrak v valju." },
  { cat: 3, q: "Kakšna je razlika med dvotaktnim in štiritaktnim motorjem?", a: "Dvotaktni motor opravi delovni ciklus v dveh taktih oziroma v enem obratu ročične gredi. Štiritaktni motor opravi delovni ciklus v štirih taktih oziroma v dveh obratih ročične gredi. Dvotaktni motor je praviloma enostavnejši in lažji, štiritaktni pa varčnejši, tišji in ima ločen sistem mazanja." },
  { cat: 3, q: "Kako vzdržujemo in pravilno uporabljamo motor?", a: "Motor vzdržujemo po navodilih proizvajalca: redno menjamo olje in filtre, preverjamo gorivo, hladilni sistem, svečke, jermene, cevi, akumulator in propeler. Pred plovbo preverimo osnovno delovanje, med plovbo spremljamo instrumente in alarme, po plovbi pa motor po potrebi speremo in pregledamo." },
  { cat: 3, q: "Katera maziva uporabljamo pri motorjih?", a: "Uporabljamo motorna olja ustrezne specifikacije, ki jo predpiše proizvajalec. Pri štiritaktnih motorjih je olje v ločenem mazalnem sistemu, pri klasičnih dvotaktnih motorjih pa se olje meša z gorivom ali ga odmerja ločen sistem za doziranje olja." },
  { cat: 2, q: "Za katera dna so primerne posamezne vrste sider?", a: "Plužno sidro in Danforth sidro dobro držita v pesku in mulju. Sidro maček je uporabno na skalnatem ali poraščenem dnu, vendar se lahko zatakne. Sidro goba je primerno za manjša plovila in mehkejše dno. Admiralitetno sidro je vsestransko, vendar večje in manj priročno za manjša plovila. Pri izbiri vedno upoštevamo tudi težo plovila, veter, valove in dolžino sidrne vrvi oziroma verige." },
  { cat: 2, q: "Kakšna je predpisana oprema čolnov glede na dolžino in namen uporabe?", a: "Predpisana oprema je odvisna od dolžine čolna, območja plovbe, namena uporabe in pogona. Osnovno vključuje rešilne jopiče oziroma rešilna sredstva, sidro in vrv, privezne vrvi, opremo za izčrpavanje vode, gasilni aparat, navigacijske luči pri nočni plovbi, signalna sredstva, osnovno orodje in predpisane listine. Večji čolni in čolni za širša območja plovbe potrebujejo več opreme." },
  { cat: 1, q: "Kako merimo temperaturo zraka?", a: "Temperaturo zraka merimo s termometrom, običajno v stopinjah Celzija. Meritev mora biti v senci in stran od neposrednega vpliva sonca, motorja ali drugih virov toplote." },
  { cat: 1, q: "Kaj nam pove vlaga in kakšna je razlika med relativno in absolutno vlago?", a: "Vlaga pove, koliko vodne pare je v zraku. Absolutna vlaga pomeni dejansko količino vodne pare v zraku, relativna vlaga pa pove, kolikšen odstotek največje možne količine vodne pare pri dani temperaturi zrak že vsebuje. Visoka relativna vlaga povečuje možnost megle, oblakov in padavin." },
  { cat: 1, q: "Kaj je zračni tlak in kako ga merimo?", a: "Zračni tlak je pritisk zraka na površino. Merimo ga z barometrom, običajno v hektopaskalih oziroma milibarih. Padanje zračnega tlaka pogosto napoveduje poslabšanje vremena, naraščanje pa stabilnejše vreme." },
  { cat: 1, q: "Kaj je veter, katere elemente merimo in katere enote uporabljamo za hitrost vetra?", a: "Veter je gibanje zraka. Pri vetru merimo predvsem smer, iz katere piha, in hitrost oziroma jakost. Hitrost vetra izražamo v metrih na sekundo, kilometrih na uro ali vozlih, jakost pa lahko ocenimo tudi po Beaufortovi lestvici." },
  { cat: 1, q: "Kakšna je razlika med burjo in burinom?", a: "Burja je hladen, suh in sunkovit veter iz severovzhodne smeri, pogosto močan in nevaren. Burin je šibkejši priobalni nočni veter, ki nastane zaradi ohlajanja kopnega in piha s kopnega proti morju. Burja je vremenski veter večjega obsega, burin pa lokalni termični veter." },
  { cat: 1, q: "Kakšna je razlika med jugom in širokom?", a: "V praksi se izraza jugo in široko pogosto uporabljata za topel in vlažen jugovzhodni veter na Jadranu. Jugo je splošno ime za ta veter, široko pa poudarja njegovo smer iz jugovzhoda in sredozemski značaj. Oba prinašata oblačnost, dež in dolge valove." },
  { cat: 1, q: "Kdaj se pojavljajo nenadne spremembe močnih vetrov?", a: "Nenadne spremembe močnih vetrov se pogosto pojavljajo ob prehodu neviht, front, ciklonov in pri lokalnih poletnih vročinskih nevihtah. Na Jadranu so posebej nevarni nenadni sunki burje, nevihtni lebič in nagle spremembe ob razvoju kumulonimbusov." },
  { cat: 1, q: "Kaj pomenita anticiklonalno in ciklonalno vreme za vetrovne razmere?", a: "Anticiklonalno vreme je povezano z visokim zračnim tlakom, stabilnejšim in pogosto jasnejšim vremenom, vendar lahko spremlja tudi burjo. Ciklonalno vreme je povezano z nizkim zračnim tlakom, oblačnostjo, padavinami in pogostejšimi močnimi vetrovi, na Jadranu pogosto z jugom ali ciklonalno burjo." },
  { cat: 1, q: "Kdaj se pojavlja megla na morju v severnem Jadranu?", a: "Megla v severnem Jadranu se pogosto pojavlja ob visoki vlagi, šibkem vetru in temperaturnih razlikah med morjem in zrakom, posebej v hladnejšem delu leta. Za plovbo je nevarna, ker močno zmanjša vidljivost in oteži oceno razdalj ter smeri drugih plovil." },
  { cat: 1, q: "Kaj so toplotne nevihte nad kopnim?", a: "Toplotne nevihte nad kopnim nastanejo zaradi močnega segrevanja tal, dviganja toplega vlažnega zraka in razvoja nevihtnih oblakov. Pogosto se pojavijo popoldne po vročem in soparnem dnevu. Na morju so nevarne zaradi sunkov vetra, hitre spremembe smeri vetra, nalivov, grmenja in slabše vidljivosti." },
];
